{
  "name": "X3T Respawn Manager",
  "description": "A Tibia-inspired respawn claim system allowing users to book hunting grounds, manage queues, and track timers with specific rules for special areas."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type RespawnCategory = 
  | "Ab'Dendriel" | "Ankrahmun" | "Carlin" | "Darashia" | "Edron" 
  | "Farmine" | "Feyrist" | "Gnomprona" | "Gray Island" | "Issavi" 
  | "Marapur" | "Oramond" | "Port Hope" | "Roshamuul" | "Rotten Blood" 
  | "Venore" | "Warzone" | "Yalahar";

export interface Claim {
  id: string;
  playerName: string;
  startTime: number; // timestamp
  durationMinutes: number;
  endTime: number; // timestamp
  isNext: boolean;
}

export interface Respawn {
  id: string;
  name: string;
  category: RespawnCategory;
  tier: number;
  isSpecial: boolean; // True for 3h 15m max, False for 2h 20m
  currentClaim: Claim | null;
  nextQueue: Claim[];
}

export interface NewClaimData {
  playerName: string;
  durationMinutes: number;
}

import { intervalToDuration, format } from 'date-fns';

export const formatTimeRemaining = (endTime: number): string => {
  const now = Date.now();
  if (now >= endTime) return "00:00";

  const duration = intervalToDuration({ start: now, end: endTime });

  const hours = duration.hours || 0;
  const minutes = duration.minutes || 0;
  // We strictly want HH:mm format usually, but simple mm is okay for short
  return `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}`;
};

export const formatEndTime = (timestamp: number): string => {
  return format(new Date(timestamp), 'HH:mm');
};

export const calculateEndTime = (startTime: number, durationMinutes: number): number => {
  return startTime + (durationMinutes * 60 * 1000);
};

import React, { useState, useEffect } from 'react';
import { X, Clock, User } from 'lucide-react';
import { NewClaimData, Respawn } from '../types';

interface ClaimModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (data: NewClaimData) => void;
  respawn: Respawn | null;
  mode: 'CLAIM' | 'NEXT';
}

const ClaimModal: React.FC<ClaimModalProps> = ({ isOpen, onClose, onSubmit, respawn, mode }) => {
  const [playerName, setPlayerName] = useState('');
  const [duration, setDuration] = useState(60); // Default 1 hour
  const [error, setError] = useState('');

  // Reset state when modal opens
  useEffect(() => {
    if (isOpen) {
      setPlayerName('');
      setDuration(60);
      setError('');
    }
  }, [isOpen]);

  if (!isOpen || !respawn) return null;

  // Constraints
  const MIN_MINUTES = 30;
  const MAX_MINUTES = respawn.isSpecial ? 195 : 140; // 3h15m or 2h20m
  const MAX_DISPLAY = respawn.isSpecial ? "3 horas e 15 minutos" : "2 horas e 20 minutos";

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!playerName.trim()) {
      setError('Nome do jogador é obrigatório.');
      return;
    }
    if (duration < MIN_MINUTES || duration > MAX_MINUTES) {
      setError(`O tempo deve ser entre 30 min e ${MAX_DISPLAY}.`);
      return;
    }
    onSubmit({ playerName, durationMinutes: duration });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4">
      <div className="bg-slate-800 border-2 border-amber-600/50 rounded-lg shadow-2xl w-full max-w-md animate-in fade-in zoom-in duration-200">
        <div className="flex justify-between items-center p-4 border-b border-slate-700 bg-slate-900/50">
          <h3 className="text-xl font-bold text-amber-500 rpg-font">
            {mode === 'CLAIM' ? 'Marcar Horário' : 'Entrar na Fila (Next)'}
          </h3>
          <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
            <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          <div className="space-y-1">
            <h4 className="text-lg font-semibold text-white">{respawn.name}</h4>
            <span className="text-xs font-mono text-slate-400 uppercase tracking-widest">{respawn.category}</span>
          </div>

          <div className="space-y-4">
            {/* Player Name */}
            <div>
              <label className="block text-sm font-medium text-slate-300 mb-1 flex items-center gap-2">
                <User size={16} /> Nome do Personagem
              </label>
              <input
                type="text"
                value={playerName}
                onChange={(e) => setPlayerName(e.target.value)}
                placeholder="Ex: Eternal Oblivion"
                className="w-full bg-slate-900 border border-slate-600 rounded-md px-3 py-2 text-white focus:ring-2 focus:ring-amber-500 focus:border-transparent outline-none transition-all"
                autoFocus
              />
            </div>

            {/* Duration */}
            <div>
              <label className="block text-sm font-medium text-slate-300 mb-1 flex items-center gap-2">
                <Clock size={16} /> Tempo de Hunt (Minutos)
              </label>
              <div className="flex items-center gap-4">
                <input
                  type="range"
                  min={MIN_MINUTES}
                  max={MAX_MINUTES}
                  step={5}
                  value={duration}
                  onChange={(e) => setDuration(Number(e.target.value))}
                  className="flex-grow h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-amber-500"
                />
                <input 
                    type="number"
                    min={MIN_MINUTES}
                    max={MAX_MINUTES}
                    value={duration}
                    onChange={(e) => setDuration(Number(e.target.value))}
                    className="w-20 bg-slate-900 border border-slate-600 rounded px-2 py-1 text-center text-white"
                />
              </div>
              <p className="text-xs text-slate-500 mt-2">
                Mín: 30m | Máx: {Math.floor(MAX_MINUTES/60)}h{MAX_MINUTES%60}m
              </p>
            </div>
          </div>

          {error && (
            <div className="p-3 bg-red-900/30 border border-red-500/50 rounded text-red-200 text-sm">
              {error}
            </div>
          )}

          <div className="flex justify-end pt-2">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 text-slate-300 hover:text-white mr-2"
            >
              Cancelar
            </button>
            <button
              type="submit"
              className="bg-amber-600 hover:bg-amber-500 text-white font-bold py-2 px-6 rounded shadow-lg shadow-amber-900/20 transition-all transform hover:scale-105"
            >
              Confirmar
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default ClaimModal;

import React, { useState, useEffect } from 'react';
import { Shield, Clock, Users, Trash2, ArrowRightCircle, Plus } from 'lucide-react';
import { Respawn } from '../types';
import { formatTimeRemaining, formatEndTime } from '../utils/time';

interface RespawnCardProps {
  respawn: Respawn;
  onClaim: (respawnId: string) => void;
  onNext: (respawnId: string) => void;
  onCancel: (respawnId: string, claimId: string, isNext: boolean) => void;
}

const RespawnCard: React.FC<RespawnCardProps> = ({ respawn, onClaim, onNext, onCancel }) => {
  const [timeLeft, setTimeLeft] = useState<string>('');

  // Update timer every minute
  useEffect(() => {
    const updateTimer = () => {
      if (respawn.currentClaim) {
        setTimeLeft(formatTimeRemaining(respawn.currentClaim.endTime));
      } else {
        setTimeLeft('');
      }
    };

    updateTimer();
    const interval = setInterval(updateTimer, 60000); // Update every minute
    return () => clearInterval(interval);
  }, [respawn.currentClaim]);

  const isOccupied = !!respawn.currentClaim;
  const statusColor = isOccupied ? 'border-red-900/50 bg-slate-800/80' : 'border-green-900/30 bg-slate-800/40';
  const headerColor = isOccupied ? 'text-red-400' : 'text-green-400';

  return (
    <div className={`relative border rounded-lg overflow-hidden transition-all duration-300 hover:shadow-lg hover:border-slate-600 ${statusColor} border-slate-700`}>

      {/* Header */}
      <div className="p-3 border-b border-slate-700/50 flex justify-between items-start">
        <div>
          <h4 className="font-bold text-slate-100 flex items-center gap-2">
             {respawn.name}
             {respawn.tier > 1 && <span className="text-[10px] bg-amber-900/60 text-amber-200 px-1.5 py-0.5 rounded border border-amber-700/50">T{respawn.tier}</span>}
             {respawn.isSpecial && <span className="text-[10px] bg-purple-900/60 text-purple-200 px-1.5 py-0.5 rounded border border-purple-700/50">SPECIAL</span>}
          </h4>
          <span className="text-xs text-slate-500 uppercase tracking-wider">{respawn.category}</span>
        </div>

        <div className={`flex items-center gap-1 ${headerColor}`}>
          <Shield size={16} fill={isOccupied ? "currentColor" : "none"} />
          <span className="text-xs font-bold">{isOccupied ? "OCUPADO" : "LIVRE"}</span>
        </div>
      </div>

      {/* Body */}
      <div className="p-3 space-y-3">
        {isOccupied && respawn.currentClaim ? (
          <div className="bg-slate-900/60 rounded p-2 border border-slate-700/50 animate-in fade-in slide-in-from-top-2 duration-300">
            <div className="flex justify-between items-center mb-1">
              <span className="font-bold text-amber-400 truncate">{respawn.currentClaim.playerName}</span>
              <button 
                onClick={() => onCancel(respawn.id, respawn.currentClaim!.id, false)}
                className="text-slate-500 hover:text-red-400 transition-colors p-1"
                title="Cancelar Horário"
              >
                <Trash2 size={14} />
              </button>
            </div>
            <div className="flex justify-between text-xs text-slate-400">
              <span className="flex items-center gap-1"><Clock size={12} /> Resta: <span className="text-white font-mono">{timeLeft}</span></span>
              <span>Fim: {formatEndTime(respawn.currentClaim.endTime)}</span>
            </div>
          </div>
        ) : (
          <div className="h-16 flex items-center justify-center text-slate-600 text-sm italic">
            Disponível para caçar
          </div>
        )}

        {/* Next Queue */}
        {respawn.nextQueue.length > 0 && (
          <div className="space-y-1 mt-2">
            <div className="flex items-center gap-1 text-xs text-slate-500 font-semibold uppercase">
              <ArrowRightCircle size={12} /> Próximos na Fila
            </div>
            {respawn.nextQueue.map((next, index) => (
              <div key={next.id} className="bg-slate-900/30 rounded px-2 py-1 text-xs border border-slate-800 flex justify-between items-center">
                 <span className="text-slate-300 truncate max-w-[120px]">
                    <span className="text-slate-500 mr-1">{index + 1}.</span> {next.playerName}
                 </span>
                 <div className="flex items-center gap-2">
                    <span className="text-slate-500 font-mono">{Math.floor(next.durationMinutes / 60)}h{next.durationMinutes % 60 > 0 ? `${next.durationMinutes % 60}m` : ''}</span>
                    <button 
                      onClick={() => onCancel(respawn.id, next.id, true)}
                      className="text-slate-600 hover:text-red-400"
                    >
                      <XIcon size={12} />
                    </button>
                 </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Footer Actions */}
      <div className="p-2 bg-slate-900/40 border-t border-slate-800 flex gap-2">
        {!isOccupied ? (
          <button 
            onClick={() => onClaim(respawn.id)}
            className="w-full bg-green-700/80 hover:bg-green-600 text-white text-sm font-semibold py-1.5 rounded transition-colors flex justify-center items-center gap-2"
          >
            <Shield size={14} /> Marcar
          </button>
        ) : (
          <button 
            onClick={() => onNext(respawn.id)}
            className="w-full bg-amber-700/20 hover:bg-amber-700/40 text-amber-500 hover:text-amber-200 border border-amber-700/50 text-sm font-semibold py-1.5 rounded transition-all flex justify-center items-center gap-2"
          >
            <Plus size={14} /> Entrar na Fila (Next)
          </button>
        )}
      </div>
    </div>
  );
};

// Helper for the small X icon inside queue
const XIcon = ({ size }: { size: number }) => (
  <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 18 18"/></svg>
);

export default RespawnCard;

import React, { useState, useEffect, useMemo } from 'react';
import { Search, Map, RefreshCw } from 'lucide-react';
import { INITIAL_RESPAWNS } from './data/respawns';
import { Respawn, NewClaimData, Claim, RespawnCategory } from './types';
import RespawnCard from './components/RespawnCard';
import ClaimModal from './components/ClaimModal';
import { calculateEndTime } from './utils/time';

function App() {
  const [respawns, setRespawns] = useState<Respawn[]>(INITIAL_RESPAWNS);
  const [modalOpen, setModalOpen] = useState(false);
  const [activeRespawnId, setActiveRespawnId] = useState<string | null>(null);
  const [modalMode, setModalMode] = useState<'CLAIM' | 'NEXT'>('CLAIM');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('ALL');

  // Categories derived from data
  const categories = useMemo(() => {
    const cats = new Set(INITIAL_RESPAWNS.map(r => r.category));
    return ['ALL', ...Array.from(cats).sort()];
  }, []);

  // Filter Logic
  const filteredRespawns = respawns.filter(respawn => {
    const matchesSearch = respawn.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                          respawn.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = selectedCategory === 'ALL' || respawn.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  // --- Handlers ---

  const handleOpenClaim = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('CLAIM');
    setModalOpen(true);
  };

  const handleOpenNext = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('NEXT');
    setModalOpen(true);
  };

  const handleCloseModal = () => {
    setModalOpen(false);
    setActiveRespawnId(null);
  };

  const handleModalSubmit = (data: NewClaimData) => {
    if (!activeRespawnId) return;

    setRespawns(prev => prev.map(r => {
      if (r.id !== activeRespawnId) return r;

      const now = Date.now();

      if (modalMode === 'CLAIM') {
        const endTime = calculateEndTime(now, data.durationMinutes);
        const newClaim: Claim = {
          id: crypto.randomUUID(),
          playerName: data.playerName,
          startTime: now,
          durationMinutes: data.durationMinutes,
          endTime: endTime,
          isNext: false
        };
        return { ...r, currentClaim: newClaim };
      } 
      else {
        // NEXT Logic
        // Start time for next is the End time of the last person in queue OR current claim
        let lastEndTime = r.currentClaim ? r.currentClaim.endTime : now;
        if (r.nextQueue.length > 0) {
          lastEndTime = r.nextQueue[r.nextQueue.length - 1].endTime;
        }

        const endTime = calculateEndTime(lastEndTime, data.durationMinutes);

        const newNext: Claim = {
            id: crypto.randomUUID(),
            playerName: data.playerName,
            startTime: lastEndTime,
            durationMinutes: data.durationMinutes,
            endTime: endTime,
            isNext: true
        };

        return { ...r, nextQueue: [...r.nextQueue, newNext] };
      }
    }));
  };

  const handleCancel = (respawnId: string, claimId: string, isNext: boolean) => {
    if(!confirm("Tem certeza que deseja desmarcar?")) return;

    setRespawns(prev => prev.map(r => {
      if (r.id !== respawnId) return r;

      if (!isNext) {
        // Cancel Current
        // If there is a queue, move the first 'next' to 'current'
        let newCurrent = null;
        let newQueue = [...r.nextQueue];

        if (newQueue.length > 0) {
          const nextUp = newQueue.shift(); // Remove first
          if (nextUp) {
            // Adjust start time to NOW since the previous person left early
            const now = Date.now();
            const adjustedEndTime = calculateEndTime(now, nextUp.durationMinutes);

            newCurrent = {
              ...nextUp,
              startTime: now,
              endTime: adjustedEndTime,
              isNext: false
            };

            // We also need to ripple update the start times of everyone else in the queue...
            // For simplicity in this demo, we'll leave the remaining queue relative to the ORIGINAL plan 
            // OR we could recalculate all. Let's recalculate for correctness.
            let previousEnd = adjustedEndTime;
            newQueue = newQueue.map(q => {
               const qEnd = calculateEndTime(previousEnd, q.durationMinutes);
               const updated = { ...q, startTime: previousEnd, endTime: qEnd };
               previousEnd = qEnd;
               return updated;
            });
          }
        }

        return { ...r, currentClaim: newCurrent, nextQueue: newQueue };
      } else {
        // Cancel from Queue
        const newQueue = r.nextQueue.filter(q => q.id !== claimId);

        // Recalculate times if we removed someone from the middle?
        // For a prototype, simple removal is okay, gaps technically just mean the next person starts earlier,
        // but physically calculating it ensures the timer displays are correct.
        // Let's do a quick recalc pass.
        let baseTime = r.currentClaim ? r.currentClaim.endTime : Date.now();
        const recalculatedQueue = newQueue.map(q => {
             const qEnd = calculateEndTime(baseTime, q.durationMinutes);
             const updated = { ...q, startTime: baseTime, endTime: qEnd };
             baseTime = qEnd;
             return updated;
        });

        return { ...r, nextQueue: recalculatedQueue };
      }
    }));
  };

  // Auto-remove expired claims every minute
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      setRespawns(prev => prev.map(r => {
        if (r.currentClaim && r.currentClaim.endTime <= now) {
          // Current expired. Move queue up.
          let newCurrent = null;
          let newQueue = [...r.nextQueue];

          if (newQueue.length > 0) {
            const nextUp = newQueue.shift();
            if (nextUp) {
               newCurrent = { ...nextUp, isNext: false };
            }
          }
          return { ...r, currentClaim: newCurrent, nextQueue: newQueue };
        }
        return r;
      }));
    }, 30000); // Check every 30s
    return () => clearInterval(interval);
  }, []);


  const activeRespawn = respawns.find(r => r.id === activeRespawnId) || null;

  return (
    <div className="min-h-screen bg-slate-950 pb-20">

      {/* Header */}
      <header className="bg-slate-900 border-b border-amber-700/30 sticky top-0 z-40 shadow-xl">
        <div className="container mx-auto px-4 py-4 flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-amber-600 rounded-lg flex items-center justify-center transform rotate-45 border-2 border-amber-400 shadow-[0_0_15px_rgba(245,158,11,0.5)]">
               <div className="transform -rotate-45 font-bold text-slate-900 text-xl">X3</div>
            </div>
            <div>
              <h1 className="text-2xl font-bold text-amber-500 tracking-wide rpg-font drop-shadow-sm">RESPAWN LIST</h1>
              <p className="text-xs text-slate-400 -mt-1 tracking-widest uppercase">Claim System</p>
            </div>
          </div>

          <div className="flex flex-col sm:flex-row gap-2 w-full md:w-auto">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input 
                type="text" 
                placeholder="Buscar respawn..." 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full sm:w-64 bg-slate-800 border border-slate-700 rounded-full py-2 pl-10 pr-4 text-sm text-slate-200 focus:ring-2 focus:ring-amber-500/50 outline-none"
              />
            </div>

            <div className="relative">
               <Map className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
               <select 
                  className="w-full sm:w-48 bg-slate-800 border border-slate-700 rounded-full py-2 pl-10 pr-8 text-sm text-slate-200 appearance-none focus:ring-2 focus:ring-amber-500/50 outline-none cursor-pointer"
                  value={selectedCategory}
                  onChange={(e) => setSelectedCategory(e.target.value)}
               >
                 {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
               </select>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-4 py-8">

        {/* Stats / Info Bar */}
        <div className="flex justify-between items-center mb-6 bg-slate-900/50 p-3 rounded-lg border border-slate-800">
           <div className="text-xs text-slate-500 flex items-center gap-2">
             <RefreshCw size={12} className="animate-spin-slow" /> 
             Última atualização: {new Date().toLocaleTimeString()}
           </div>
           <div className="flex gap-4 text-xs font-semibold">
              <span className="text-green-500 flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-green-500"></span> Livre</span>
              <span className="text-red-500 flex items-center gap-1"><span className="w-2 h-2 rounded-full bg-red-500"></span> Ocupado</span>
           </div>
        </div>

        {/* Grid */}
        {filteredRespawns.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {filteredRespawns.map(respawn => (
              <RespawnCard 
                key={respawn.id} 
                respawn={respawn}
                onClaim={handleOpenClaim}
                onNext={handleOpenNext}
                onCancel={handleCancel}
              />
            ))}
          </div>
        ) : (
          <div className="text-center py-20 text-slate-500">
             <p className="text-lg">Nenhum respawn encontrado.</p>
             <button onClick={() => {setSearchQuery(''); setSelectedCategory('ALL');}} className="mt-2 text-amber-500 hover:underline">Limpar filtros</button>
          </div>
        )}
      </main>

      <ClaimModal 
        isOpen={modalOpen}
        onClose={handleCloseModal}
        onSubmit={handleModalSubmit}
        respawn={activeRespawn}
        mode={modalMode}
      />

    </div>
  );
}

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Search, Map, RefreshCw, ChevronUp } from 'lucide-react';
import { INITIAL_RESPAWNS } from './data/respawns';
import { Respawn, NewClaimData, Claim, RespawnCategory } from './types';
import RespawnCard from './components/RespawnCard';
import ClaimModal from './components/ClaimModal';
import { calculateEndTime } from './utils/time';

function App() {
  const [respawns, setRespawns] = useState<Respawn[]>(INITIAL_RESPAWNS);
  const [modalOpen, setModalOpen] = useState(false);
  const [activeRespawnId, setActiveRespawnId] = useState<string | null>(null);
  const [modalMode, setModalMode] = useState<'CLAIM' | 'NEXT'>('CLAIM');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('ALL');

  // Categories derived from data
  const categories = useMemo(() => {
    const cats = new Set(INITIAL_RESPAWNS.map(r => r.category));
    return ['ALL', ...Array.from(cats).sort()];
  }, []);

  // Filter Logic
  const filteredRespawns = respawns.filter(respawn => {
    const matchesSearch = respawn.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                          respawn.id.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = selectedCategory === 'ALL' || respawn.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  // --- Handlers ---

  const handleOpenClaim = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('CLAIM');
    setModalOpen(true);
  };

  const handleOpenNext = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('NEXT');
    setModalOpen(true);
  };

  const handleCloseModal = () => {
    setModalOpen(false);
    setActiveRespawnId(null);
  };

  const handleModalSubmit = (data: NewClaimData) => {
    if (!activeRespawnId) return;

    setRespawns(prev => prev.map(r => {
      if (r.id !== activeRespawnId) return r;

      const now = Date.now();

      if (modalMode === 'CLAIM') {
        const endTime = calculateEndTime(now, data.durationMinutes);
        const newClaim: Claim = {
          id: crypto.randomUUID(),
          playerName: data.playerName,
          startTime: now,
          durationMinutes: data.durationMinutes,
          endTime: endTime,
          isNext: false
        };
        return { ...r, currentClaim: newClaim };
      } 
      else {
        // NEXT Logic
        // Start time for next is the End time of the last person in queue OR current claim
        let lastEndTime = r.currentClaim ? r.currentClaim.endTime : now;
        if (r.nextQueue.length > 0) {
          lastEndTime = r.nextQueue[r.nextQueue.length - 1].endTime;
        }

        const endTime = calculateEndTime(lastEndTime, data.durationMinutes);

        const newNext: Claim = {
            id: crypto.randomUUID(),
            playerName: data.playerName,
            startTime: lastEndTime,
            durationMinutes: data.durationMinutes,
            endTime: endTime,
            isNext: true
        };

        return { ...r, nextQueue: [...r.nextQueue, newNext] };
      }
    }));
  };

  const handleCancel = (respawnId: string, claimId: string, isNext: boolean) => {
    if(!confirm("Tem certeza que deseja desmarcar?")) return;

    setRespawns(prev => prev.map(r => {
      if (r.id !== respawnId) return r;

      if (!isNext) {
        // Cancel Current
        // If there is a queue, move the first 'next' to 'current'
        let newCurrent = null;
        let newQueue = [...r.nextQueue];

        if (newQueue.length > 0) {
          const nextUp = newQueue.shift(); // Remove first
          if (nextUp) {
            // Adjust start time to NOW since the previous person left early
            const now = Date.now();
            const adjustedEndTime = calculateEndTime(now, nextUp.durationMinutes);

            newCurrent = {
              ...nextUp,
              startTime: now,
              endTime: adjustedEndTime,
              isNext: false
            };

            // We also need to ripple update the start times of everyone else in the queue...
            let previousEnd = adjustedEndTime;
            newQueue = newQueue.map(q => {
               const qEnd = calculateEndTime(previousEnd, q.durationMinutes);
               const updated = { ...q, startTime: previousEnd, endTime: qEnd };
               previousEnd = qEnd;
               return updated;
            });
          }
        }

        return { ...r, currentClaim: newCurrent, nextQueue: newQueue };
      } else {
        // Cancel from Queue
        const newQueue = r.nextQueue.filter(q => q.id !== claimId);

        // Recalculate times
        let baseTime = r.currentClaim ? r.currentClaim.endTime : Date.now();
        const recalculatedQueue = newQueue.map(q => {
             const qEnd = calculateEndTime(baseTime, q.durationMinutes);
             const updated = { ...q, startTime: baseTime, endTime: qEnd };
             baseTime = qEnd;
             return updated;
        });

        return { ...r, nextQueue: recalculatedQueue };
      }
    }));
  };

  // Auto-remove expired claims every minute
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      setRespawns(prev => prev.map(r => {
        if (r.currentClaim && r.currentClaim.endTime <= now) {
          // Current expired. Move queue up.
          let newCurrent = null;
          let newQueue = [...r.nextQueue];

          if (newQueue.length > 0) {
            const nextUp = newQueue.shift();
            if (nextUp) {
               newCurrent = { ...nextUp, isNext: false };
            }
          }
          return { ...r, currentClaim: newCurrent, nextQueue: newQueue };
        }
        return r;
      }));
    }, 30000); // Check every 30s
    return () => clearInterval(interval);
  }, []);


  const activeRespawn = respawns.find(r => r.id === activeRespawnId) || null;

  return (
    <div className="min-h-screen bg-[#0b1121] pb-20 selection:bg-cyan-500/30">

      {/* Header */}
      <header className="bg-[#0f172a]/80 backdrop-blur-md border-b border-cyan-900/30 sticky top-0 z-40 shadow-[0_4px_20px_-5px_rgba(8,145,178,0.1)]">
        <div className="container mx-auto px-4 py-3 flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-4">
            {/* MAJOR Logo */}
            <div className="relative group">
              <div className="absolute -inset-1 bg-gradient-to-r from-cyan-500 to-blue-600 rounded-lg blur opacity-40 group-hover:opacity-75 transition duration-200"></div>
              <div className="relative w-12 h-12 bg-[#0b1121] rounded-lg border border-cyan-800 flex flex-col items-center justify-center shadow-lg">
                 <ChevronUp size={28} className="text-cyan-400 -mb-2" strokeWidth={3} />
                 <span className="text-[10px] font-bold text-cyan-500 tracking-wider">MJR</span>
              </div>
            </div>

            <div>
              <h1 className="text-3xl font-bold text-white tracking-wider digital-font drop-shadow-[0_0_10px_rgba(34,211,238,0.3)]">
                CLAIMED
              </h1>
              <div className="flex items-center gap-2">
                <div className="h-[2px] w-4 bg-cyan-500 rounded-full"></div>
                <p className="text-[10px] text-cyan-400/80 tracking-[0.2em] uppercase font-bold">System Manager</p>
              </div>
            </div>
          </div>

          <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
            <div className="relative group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-cyan-700 group-focus-within:text-cyan-400 transition-colors" size={18} />
              <input 
                type="text" 
                placeholder="BUSCAR RESPAWN..." 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full sm:w-64 bg-[#1e293b]/50 border border-slate-700/50 rounded-md py-2 pl-10 pr-4 text-sm text-cyan-100 placeholder-slate-500 focus:border-cyan-500/50 focus:ring-1 focus:ring-cyan-500/50 outline-none transition-all uppercase tracking-wide font-medium"
              />
            </div>

            <div className="relative group">
               <Map className="absolute left-3 top-1/2 -translate-y-1/2 text-cyan-700 group-focus-within:text-cyan-400 transition-colors" size={18} />
               <select 
                  className="w-full sm:w-48 bg-[#1e293b]/50 border border-slate-700/50 rounded-md py-2 pl-10 pr-8 text-sm text-cyan-100 appearance-none focus:border-cyan-500/50 focus:ring-1 focus:ring-cyan-500/50 outline-none cursor-pointer uppercase tracking-wide font-medium"
                  value={selectedCategory}
                  onChange={(e) => setSelectedCategory(e.target.value)}
               >
                 {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
               </select>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-4 py-8">

        {/* Stats / Info Bar */}
        <div className="flex flex-wrap justify-between items-center mb-6 bg-[#1e293b]/30 p-4 rounded-md border-l-4 border-cyan-500 backdrop-blur-sm">
           <div className="text-xs text-cyan-600/80 flex items-center gap-2 uppercase tracking-wider font-bold">
             <RefreshCw size={12} className="animate-spin-slow" /> 
             System Status: Online | {new Date().toLocaleTimeString()}
           </div>
           <div className="flex gap-6 text-xs font-bold uppercase tracking-wider">
              <span className="text-emerald-400 flex items-center gap-2 drop-shadow-sm">
                <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 shadow-[0_0_8px_rgba(52,211,153,0.8)]"></span> 
                Available
              </span>
              <span className="text-rose-500 flex items-center gap-2 drop-shadow-sm">
                <span className="w-1.5 h-1.5 rounded-full bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.8)]"></span> 
                Occupied
              </span>
           </div>
        </div>

        {/* Grid */}
        {filteredRespawns.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {filteredRespawns.map(respawn => (
              <RespawnCard 
                key={respawn.id} 
                respawn={respawn}
                onClaim={handleOpenClaim}
                onNext={handleOpenNext}
                onCancel={handleCancel}
              />
            ))}
          </div>
        ) : (
          <div className="text-center py-24 text-slate-600">
             <div className="inline-block p-4 rounded-full bg-slate-900/50 mb-4">
               <Search size={32} className="opacity-50" />
             </div>
             <p className="text-lg font-medium">NENHUM RESULTADO ENCONTRADO</p>
             <button onClick={() => {setSearchQuery(''); setSelectedCategory('ALL');}} className="mt-4 text-cyan-500 hover:text-cyan-400 underline decoration-dotted underline-offset-4 text-sm font-bold uppercase tracking-wider">
               Limpar filtros
             </button>
          </div>
        )}
      </main>

      <ClaimModal 
        isOpen={modalOpen}
        onClose={handleCloseModal}
        onSubmit={handleModalSubmit}
        respawn={activeRespawn}
        mode={modalMode}
      />

    </div>
  );
}

