        ) : (
          <div className="text-center py-24 text-slate-600 border border-dashed border-slate-800 rounded-xl bg-slate-900/20">
             <div className="inline-block p-4 rounded-full bg-slate-900/50 mb-4 shadow-inner">
               <Search size={32} className="opacity-50" />
             </div>
             <p className="text-lg font-medium text-slate-400">
               {filterStatus === 'OCCUPIED' ? 'NO ACTIVE CLAIMS' : 'NO RESULTS FOUND'}
             </p>
             <p className="text-xs uppercase tracking-widest text-slate-600 mt-1">
               {filterStatus === 'OCCUPIED' ? 'The hunting grounds are currently clear.' : 'Try adjusting your search criteria.'}
             </p>

             {filterStatus === 'OCCUPIED' ? (
                <button 
                    onClick={() => setFilterStatus('FREE')} 
                    className="mt-6 bg-cyan-900/30 hover:bg-cyan-900/50 text-cyan-400 border border-cyan-800/50 px-6 py-2 rounded-full text-xs font-bold uppercase tracking-wider transition-all flex items-center gap-2 mx-auto hover:scale-105"
                >
