                    className="mt-6 text-cyan-500 hover:text-cyan-400 hover:underline decoration-dotted underline-offset-4 text-xs font-bold uppercase tracking-wider transition-all"
                >
                    Reset System Filters
                </button>
             )}
          </div>
        )}
      </main>

      <ClaimModal 
        isOpen={modalOpen}
        onClose={handleCloseModal}
        onSubmit={handleModalSubmit}
        respawn={activeRespawn}
        mode={modalMode}
      />

    </div>
  );
}

