                            onClick={(e) => {
                                e.stopPropagation();
                                onCancel(respawn.id, next.id, true);
                            }}
                            className="text-slate-600 hover:text-rose-400 opacity-0 group-hover/item:opacity-100 transition-opacity p-1"
                        >
                            <XIcon size={12} />
                        </button>
                    </div>
                </div>
                ))}
            </div>
          </div>
        )}
      </div>

      {/* Footer Actions */}
      <div className="p-2 bg-slate-950/30 border-t border-slate-800/50">
        {!isOccupied ? (
          <button 
            type="button"
            onClick={() => onClaim(respawn.id)}
            className="w-full bg-cyan-600 hover:bg-cyan-500 text-white text-xs font-bold uppercase tracking-wider py-2 rounded shadow-[0_0_10px_rgba(8,145,178,0.2)] hover:shadow-[0_0_15px_rgba(34,211,238,0.4)] transition-all flex justify-center items-center gap-2 group/btn"
          >
            <Shield size={14} className="group-hover/btn:scale-110 transition-transform" /> Claim Spot
          </button>
        ) : (
          <>
            {/* If released early and queue exists, show Anticipate Button */}
            {isReleased && respawn.nextQueue.length > 0 && onAnticipate ? (
                 <button 
                 type="button"
                 onClick={() => onAnticipate(respawn.id)}
                 className="w-full bg-amber-600 hover:bg-amber-500 text-white text-xs font-bold uppercase tracking-wider py-2 rounded shadow-[0_0_10px_rgba(245,158,11,0.2)] animate-pulse hover:animate-none transition-all flex justify-center items-center gap-2"
               >
                 <PlayCircle size={14} /> Antecipar / Start Now
               </button>
            ) : (
                <button 
                type="button"
                onClick={() => onNext(respawn.id)}
                className="w-full bg-slate-800 hover:bg-slate-700 text-cyan-400 hover:text-cyan-300 border border-slate-700 hover:border-cyan-500/30 text-xs font-bold uppercase tracking-wider py-2 rounded transition-all flex justify-center items-center gap-2"
              >
                <Plus size={14} /> Add Next
              </button>
            )}
          </>
        )}
      </div>
    </div>
  );
};

// Helper for the small X icon inside queue
const XIcon = ({ size }: { size: number }) => (
  <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 18 18"/></svg>
);

export default RespawnCard;

import React, { useState, useEffect, useMemo } from 'react';
import { RefreshCw, ChevronUp, Plus, Search } from 'lucide-react';
import { INITIAL_RESPAWNS } from './data/respawns';
import { Respawn, NewClaimData, Claim } from './types';
import RespawnCard from './components/RespawnCard';
import ClaimModal from './components/ClaimModal';
import RespawnSelector from './components/RespawnSelector';
import { calculateEndTime } from './utils/time';

function App() {
  const [respawns, setRespawns] = useState<Respawn[]>(INITIAL_RESPAWNS);

  // Modal States
  const [claimModalOpen, setClaimModalOpen] = useState(false);
  const [selectorOpen, setSelectorOpen] = useState(false);

  const [activeRespawnId, setActiveRespawnId] = useState<string | null>(null);
  const [modalMode, setModalMode] = useState<'CLAIM' | 'NEXT'>('CLAIM');

  // --- Derived Data ---

  // Main View: Only show OCCUPIED respawns
  const occupiedRespawns = respawns.filter(r => !!r.currentClaim);

  // Selector View: Only show FREE respawns
  const freeRespawns = respawns.filter(r => !r.currentClaim);

  // --- Handlers ---

  const handleOpenSelector = () => {
    setSelectorOpen(true);
  };

  const handleSelectFromList = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('CLAIM');
    setSelectorOpen(false); 
    setClaimModalOpen(true); 
  };

  const handleOpenClaim = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('CLAIM');
    setClaimModalOpen(true);
  };

  const handleOpenNext = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('NEXT');
    setClaimModalOpen(true);
  };

  const handleCloseModals = () => {
    setClaimModalOpen(false);
    setSelectorOpen(false);
    setActiveRespawnId(null);
  };

  const handleModalSubmit = (data: NewClaimData) => {
    if (!activeRespawnId) return;

    setRespawns(prev => prev.map(r => {
      if (r.id !== activeRespawnId) return r;

      const now = Date.now();

      if (modalMode === 'CLAIM') {
        const endTime = calculateEndTime(now, data.durationMinutes);
        const newClaim: Claim = {
          id: crypto.randomUUID(),
          playerName: data.playerName,
          startTime: now,
          durationMinutes: data.durationMinutes,
          endTime: endTime,
          isNext: false
        };
        return { ...r, currentClaim: newClaim };
      } 
      else {
        // NEXT Logic
        let lastEndTime = r.currentClaim ? r.currentClaim.endTime : now;
        if (r.nextQueue.length > 0) {
          lastEndTime = r.nextQueue[r.nextQueue.length - 1].endTime;
        }

        const endTime = calculateEndTime(lastEndTime, data.durationMinutes);

        const newNext: Claim = {
            id: crypto.randomUUID(),
            playerName: data.playerName,
            startTime: lastEndTime,
            durationMinutes: data.durationMinutes,
            endTime: endTime,
            isNext: true
        };

        return { ...r, nextQueue: [...r.nextQueue, newNext] };
      }
    }));
  };

  // Logic:
  // If no queue: Remove Current.
  // If queue exists: Mark Current as "releasedEarly" (Yellow state).
  // If cancelling a Next item: Remove from queue.
  const handleCancel = (respawnId: string, claimId: string, isNext: boolean) => {
    // Explicit window.confirm
    if(!window.confirm("Tem certeza que deseja desmarcar?")) return;

    setRespawns(prev => {
        return prev.map(r => {
            if (r.id !== respawnId) return r;

            if (!isNext) {
                // Cancel Current
                if (r.nextQueue.length === 0) {
                    // Case 1: No queue, just clear it
                    return { ...r, currentClaim: null };
                } else {
                    // Case 2: Queue exists, switch to YELLOW (Released) state
                    // Keep the current claim data, just flag it
                    if (!r.currentClaim) return r;
                    return { 
                        ...r, 
                        currentClaim: { ...r.currentClaim, releasedEarly: true } 
                    };
                }
            } else {
                // Cancel from Queue
                const newQueue = r.nextQueue.filter(q => q.id !== claimId);

                // Recalculate times if we removed someone from the middle of the queue
                let baseTime = r.currentClaim ? r.currentClaim.endTime : Date.now();
                const recalculatedQueue = newQueue.map(q => {
                    const qEnd = calculateEndTime(baseTime, q.durationMinutes);
                    const updated = { ...q, startTime: baseTime, endTime: qEnd };
                    baseTime = qEnd;
                    return updated;
                });

                return { ...r, nextQueue: recalculatedQueue };
            }
        });
    });
  };

  // New Logic: The Next person clicks "Anticipate" on a Yellow card
  const handleAnticipate = (respawnId: string) => {
    setRespawns(prev => prev.map(r => {
        if (r.id !== respawnId) return r;
        if (r.nextQueue.length === 0) return r;

        // Move next[0] to current
        const nextUp = r.nextQueue[0];
        const remainingQueue = r.nextQueue.slice(1);
        const now = Date.now();
        const newEndTime = calculateEndTime(now, nextUp.durationMinutes);

        const newCurrent: Claim = {
            ...nextUp,
            startTime: now,
            endTime: newEndTime,
            isNext: false,
            releasedEarly: false
        };

        // Recalculate remaining queue times based on newCurrent end time
        let previousEnd = newEndTime;
        const recalculatedQueue = remainingQueue.map(q => {
            const qEnd = calculateEndTime(previousEnd, q.durationMinutes);
            const updated = { ...q, startTime: previousEnd, endTime: qEnd };
            previousEnd = qEnd;
            return updated;
        });

        return { ...r, currentClaim: newCurrent, nextQueue: recalculatedQueue };
    }));
  };

  // Auto-remove expired claims every minute
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      setRespawns(prev => prev.map(r => {
        if (r.currentClaim && r.currentClaim.endTime <= now) {
          // Current expired. Move queue up.
          let newCurrent = null;
          let newQueue = [...r.nextQueue];

          if (newQueue.length > 0) {
            const nextUp = newQueue.shift();
            if (nextUp) {
               newCurrent = { ...nextUp, isNext: false };
            }
          }
          return { ...r, currentClaim: newCurrent, nextQueue: newQueue };
        }
        return r;
      }));
    }, 30000); // Check every 30s
    return () => clearInterval(interval);
  }, []);


  const activeRespawn = respawns.find(r => r.id === activeRespawnId) || null;

  return (
    <div className="min-h-screen bg-[#0b1121] pb-20 selection:bg-cyan-500/30">

      {/* Header */}
      <header className="bg-[#0f172a]/80 backdrop-blur-md border-b border-cyan-900/30 sticky top-0 z-40 shadow-[0_4px_20px_-5px_rgba(8,145,178,0.1)]">
        <div className="container mx-auto px-4 py-3 flex flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-4">
            {/* MAJOR Logo */}
            <div className="relative group shrink-0 hidden sm:block">
              <div className="absolute -inset-1 bg-gradient-to-r from-cyan-500 to-blue-600 rounded-lg blur opacity-40 group-hover:opacity-75 transition duration-200"></div>
              <div className="relative w-12 h-12 bg-[#0b1121] rounded-lg border border-cyan-800 flex flex-col items-center justify-center shadow-lg">
                 <ChevronUp size={28} className="text-cyan-400 -mb-2" strokeWidth={3} />
                 <span className="text-[10px] font-bold text-cyan-500 tracking-wider">MJR</span>
              </div>
            </div>

            <div>
              <h1 className="text-2xl sm:text-3xl font-bold text-white tracking-wider digital-font drop-shadow-[0_0_10px_rgba(34,211,238,0.3)]">
                CLAIMED
              </h1>
              <div className="flex items-center gap-2">
                <div className="h-[2px] w-4 bg-cyan-500 rounded-full"></div>
                <p className="text-[10px] text-cyan-400/80 tracking-[0.2em] uppercase font-bold">Live Monitor</p>
              </div>
            </div>
          </div>

          {/* New Claim Action Button */}
          <button 
            onClick={handleOpenSelector}
            className="group relative inline-flex items-center justify-center gap-2 px-6 py-3 font-bold text-white transition-all duration-200 bg-cyan-600 font-lg rounded-lg hover:bg-cyan-500 hover:shadow-[0_0_20px_rgba(8,145,178,0.4)] focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-cyan-600 focus:ring-offset-slate-900"
          >
            <span className="absolute inset-0 w-full h-full -mt-1 rounded-lg opacity-30 bg-gradient-to-b from-transparent via-transparent to-black"></span>
            <Plus size={20} className="relative group-hover:rotate-90 transition-transform" strokeWidth={3} />
            <span className="relative uppercase tracking-widest text-sm">Novo Claim</span>
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-4 py-8">

        {/* Info Bar */}
        <div className="flex justify-between items-center mb-6 bg-[#1e293b]/30 p-4 rounded-md border-l-4 border-cyan-500 backdrop-blur-sm shadow-lg">
           <div className="text-xs text-cyan-600/80 flex items-center gap-2 uppercase tracking-wider font-bold">
             <RefreshCw size={12} className="animate-spin-slow" /> 
             System Active
           </div>
           <div className="text-xs font-bold uppercase tracking-wider text-slate-400">
              Occupied Spots: <span className="text-white">{occupiedRespawns.length}</span>
           </div>
        </div>

        {/* Occupied Grid */}
        {occupiedRespawns.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {occupiedRespawns.map(respawn => (
              <RespawnCard 
                key={respawn.id} 
                respawn={respawn}
                onClaim={handleOpenClaim} // Won't be used since card is occupied
                onNext={handleOpenNext}
                onCancel={handleCancel}
                onAnticipate={handleAnticipate}
              />
            ))}
          </div>
        ) : (
          <div className="text-center py-24 text-slate-600 border border-dashed border-slate-800 rounded-xl bg-slate-900/20">
             <div className="inline-block p-4 rounded-full bg-slate-900/50 mb-4 shadow-inner">
               <Search size={32} className="opacity-50" />
             </div>
             <p className="text-lg font-medium text-slate-400">NO ACTIVE CLAIMS</p>
             <p className="text-xs uppercase tracking-widest text-slate-600 mt-1 mb-6">All hunting grounds are currently free.</p>

             <button 
                onClick={handleOpenSelector}
                className="inline-flex items-center gap-2 text-cyan-400 hover:text-cyan-300 border border-cyan-900/50 hover:border-cyan-500/50 px-6 py-2 rounded uppercase font-bold text-xs tracking-widest transition-all"
             >
               <Plus size={14} /> Start a Session
             </button>
          </div>
        )}
      </main>

      {/* Modals */}
      <ClaimModal 
        isOpen={claimModalOpen}
        onClose={handleCloseModals}
        onSubmit={handleModalSubmit}
        respawn={activeRespawn}
        mode={modalMode}
      />

      <RespawnSelector 
        isOpen={selectorOpen}
        onClose={() => setSelectorOpen(false)}
        respawns={freeRespawns}
        onSelect={handleSelectFromList}
      />

    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { Shield, Clock, Trash2, ArrowRight, Plus, Activity, PlayCircle } from 'lucide-react';
import { Respawn } from '../types';
import { formatTimeRemaining, formatEndTime } from '../utils/time';

interface RespawnCardProps {
  respawn: Respawn;
  onClaim: (respawnId: string) => void;
  onNext: (respawnId: string) => void;
  onCancel: (respawnId: string, claimId: string, isNext: boolean) => void;
  onAnticipate?: (respawnId: string) => void;
}

const RespawnCard: React.FC<RespawnCardProps> = ({ respawn, onClaim, onNext, onCancel, onAnticipate }) => {
  const [timeLeft, setTimeLeft] = useState<string>('');

  // Update timer every minute
  useEffect(() => {
    const updateTimer = () => {
      if (respawn.currentClaim) {
        setTimeLeft(formatTimeRemaining(respawn.currentClaim.endTime));
      } else {
        setTimeLeft('');
      }
    };

    updateTimer();
    const interval = setInterval(updateTimer, 60000); // Update every minute
    return () => clearInterval(interval);
  }, [respawn.currentClaim]);

  const isOccupied = !!respawn.currentClaim;
  const isReleased = respawn.currentClaim?.releasedEarly || false;

  // Dynamic styles based on state
  let containerBorder = 'border-cyan-900/30 hover:border-cyan-500/50';
  let containerBg = 'bg-gradient-to-b from-[#0f172a] to-[#0f172a]';
  let statusColor = 'text-emerald-400';
  let headerBg = 'bg-cyan-950/10';
  let statusText = "FREE";

  if (isOccupied) {
    if (isReleased) {
        // YELLOW / AMBER STATE
        containerBorder = 'border-amber-600/50 hover:border-amber-500/60';
        containerBg = 'bg-gradient-to-b from-[#1a1505] to-[#0f172a]';
        statusColor = 'text-amber-400';
        headerBg = 'bg-amber-950/20';
        statusText = "OPEN FOR NEXT";
    } else {
        // RED STATE
        containerBorder = 'border-rose-900/50 hover:border-rose-700/50';
        containerBg = 'bg-gradient-to-b from-[#1a1115] to-[#0f172a]';
        statusColor = 'text-rose-500';
        headerBg = 'bg-rose-950/20';
        statusText = "TAKEN";
    }
  }

  return (
    <div className={`relative border rounded bg-slate-900 overflow-hidden transition-all duration-300 group ${containerBorder} ${containerBg}`}>

      {/* Decorative corner accent */}
      {!isOccupied && <div className="absolute top-0 right-0 w-16 h-16 bg-gradient-to-bl from-cyan-500/10 to-transparent -mr-8 -mt-8 rounded-full blur-xl group-hover:from-cyan-400/20 transition-all"></div>}

      {/* Header */}
      <div className={`p-3 border-b border-slate-800 flex justify-between items-start ${headerBg}`}>
        <div className="z-10">
          <h4 className="font-bold text-slate-100 flex items-center gap-2 digital-font tracking-wide text-lg">
             {respawn.name}
             {respawn.tier > 1 && <span className="text-[9px] bg-slate-800 text-cyan-300 px-1.5 py-0.5 rounded border border-cyan-900 font-mono">T{respawn.tier}</span>}
          </h4>
          <div className="flex items-center gap-2 mt-0.5">
            <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{respawn.category}</span>
            {respawn.isSpecial && <span className="text-[9px] text-purple-400 font-bold uppercase tracking-wider border border-purple-900/50 px-1 rounded bg-purple-900/10">Special</span>}
          </div>
        </div>

        <div className={`flex items-center gap-1.5 ${statusColor} bg-slate-950/50 px-2 py-1 rounded border border-slate-800 shadow-inner`}>
          <Activity size={14} className={isOccupied ? "" : "animate-pulse"} />
          <span className="text-[10px] font-bold uppercase tracking-wider">{statusText}</span>
        </div>
      </div>

      {/* Body */}
      <div className="p-4 space-y-4">
        {isOccupied && respawn.currentClaim ? (
          <div className={`rounded border-l-2 p-3 shadow-lg relative overflow-hidden group/card ${isReleased ? 'bg-[#1a1205] border-amber-500' : 'bg-[#0b1121] border-rose-500'}`}>
            {/* Background pattern */}
            <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-20 pointer-events-none"></div>

            <div className="relative z-10 pl-1 pr-8">
                {/* Header Row with Player Name */}
                <div className="flex items-center mb-2 h-6">
                    <span className={`font-bold truncate text-sm tracking-wide ${isReleased ? 'text-amber-100 line-through opacity-70' : 'text-rose-100'}`}>
                        {respawn.currentClaim.playerName}
                    </span>
                </div>

                {/* ABSOLUTE POSITIONED TRASH BUTTON - Ensures it's always clickable */}
                {!isReleased && (
                    <button 
                        type="button"
                        onClick={(e) => {
                            e.preventDefault();
                            e.stopPropagation();
                            onCancel(respawn.id, respawn.currentClaim!.id, false);
                        }}
                        className="absolute top-2 right-2 text-slate-400 hover:text-rose-500 hover:bg-rose-950/80 bg-slate-900/30 transition-all p-1.5 rounded cursor-pointer z-50 border border-transparent hover:border-rose-500/50"
                        title="Desmarcar / Sair da Hunt"
                    >
                        <Trash2 size={16} />
                    </button>
                )}

                {isReleased && (
                    <div className="text-[10px] font-bold text-amber-500 uppercase tracking-widest mb-2 flex items-center gap-1">
                        <span className="w-1.5 h-1.5 rounded-full bg-amber-500 animate-pulse"></span>
                        Player Left • Slot Available
                    </div>
                )}

                <div className="flex justify-between items-end text-xs mt-3">
                    <div className="flex flex-col">
                        <span className="text-slate-500 text-[10px] uppercase font-bold">Time Left</span>
                        <span className={`font-mono text-lg leading-none ${isReleased ? 'text-amber-400' : 'text-rose-400'}`}>{timeLeft}</span>
                    </div>
                    <div className="flex flex-col items-end">
                        <span className="text-slate-500 text-[10px] uppercase font-bold">End Time</span>
                        <span className="text-slate-300 font-mono">{formatEndTime(respawn.currentClaim.endTime)}</span>
                    </div>
                </div>
            </div>
          </div>
        ) : (
          <div className="h-20 flex flex-col items-center justify-center text-slate-700 border border-dashed border-slate-800 rounded bg-slate-900/30">
            <span className="text-sm font-medium">System Ready</span>
            <span className="text-[10px] uppercase tracking-widest opacity-60">Waiting for input</span>
          </div>
        )}

        {/* Next Queue */}
        {respawn.nextQueue.length > 0 && (
          <div className="space-y-2 mt-3 pt-3 border-t border-slate-800/50">
            <div className="flex items-center gap-2 text-[10px] text-cyan-600 font-bold uppercase tracking-widest">
              <ArrowRight size={10} /> Queue List ({respawn.nextQueue.length})
            </div>
            <div className="space-y-1.5">
                {respawn.nextQueue.map((next, index) => (
                <div key={next.id} className="bg-slate-800/40 rounded px-2 py-1.5 text-xs border border-slate-700/50 flex justify-between items-center group/item hover:border-slate-600 transition-colors">
                    <div className="flex items-center gap-2 overflow-hidden">
                        <span className="text-cyan-700 font-mono text-[10px]">{String(index + 1).padStart(2, '0')}</span>
                        <span className="text-slate-300 truncate max-w-[100px] font-medium">{next.playerName}</span>
                    </div>
                    <div className="flex items-center gap-3">
                        <span className="text-slate-500 font-mono text-[10px] bg-slate-900 px-1 rounded">{Math.floor(next.durationMinutes / 60)}h{next.durationMinutes % 60 > 0 ? `${next.durationMinutes % 60}m` : ''}</span>
                        <button 
                            type="button"
                            onClick={(e) => {
                                e.stopPropagation();
                                onCancel(respawn.id, next.id, true);
                            }}
                            className="text-slate-600 hover:text-rose-400 opacity-0 group-hover/item:opacity-100 transition-opacity p-1 cursor-pointer"
                        >
                            <XIcon size={12} />
                        </button>
                    </div>
                </div>
                ))}
            </div>
          </div>
        )}
      </div>

      {/* Footer Actions */}
      <div className="p-2 bg-slate-950/30 border-t border-slate-800/50">
        {!isOccupied ? (
          <button 
            type="button"
            onClick={() => onClaim(respawn.id)}
            className="w-full bg-cyan-600 hover:bg-cyan-500 text-white text-xs font-bold uppercase tracking-wider py-2 rounded shadow-[0_0_10px_rgba(8,145,178,0.2)] hover:shadow-[0_0_15px_rgba(34,211,238,0.4)] transition-all flex justify-center items-center gap-2 group/btn"
          >
            <Shield size={14} className="group-hover/btn:scale-110 transition-transform" /> Claim Spot
          </button>
        ) : (
          <>
            {/* If released early and queue exists, show Anticipate Button */}
            {isReleased && respawn.nextQueue.length > 0 && onAnticipate ? (
                 <button 
                 type="button"
                 onClick={() => onAnticipate(respawn.id)}
                 className="w-full bg-amber-600 hover:bg-amber-500 text-white text-xs font-bold uppercase tracking-wider py-2 rounded shadow-[0_0_10px_rgba(245,158,11,0.2)] animate-pulse hover:animate-none transition-all flex justify-center items-center gap-2"
               >
                 <PlayCircle size={14} /> Antecipar / Start Now
               </button>
            ) : (
                <button 
                type="button"
                onClick={() => onNext(respawn.id)}
                className="w-full bg-slate-800 hover:bg-slate-700 text-cyan-400 hover:text-cyan-300 border border-slate-700 hover:border-cyan-500/30 text-xs font-bold uppercase tracking-wider py-2 rounded transition-all flex justify-center items-center gap-2"
              >
                <Plus size={14} /> Add Next
              </button>
            )}
          </>
        )}
      </div>
    </div>
  );
};

