    setRespawns(prev => prev.map(r => {
        if (r.id !== respawnId) return r;
        if (r.nextQueue.length === 0) return r;

        const now = Date.now();

        // 1. Calculate Bonus Time (Residual from previous player)
        let bonusMinutes = 0;
        if (r.currentClaim && r.currentClaim.endTime > now) {
            const diffMs = r.currentClaim.endTime - now;
            bonusMinutes = Math.floor(diffMs / (1000 * 60));
            // Safety check: avoid negative bonus if logic desyncs
            if (bonusMinutes < 0) bonusMinutes = 0;
        }

        // 2. Get next player and remaining queue
        const nextUp = r.nextQueue[0];
        const remainingQueue = r.nextQueue.slice(1);

        // 3. Create new Current Claim (Original Duration + Bonus)
        const newDuration = nextUp.durationMinutes + bonusMinutes;
        const newEndTime = calculateEndTime(now, newDuration);

        const newCurrent: Claim = {
            ...nextUp,
            startTime: now,
            durationMinutes: newDuration, // Summed duration
            endTime: newEndTime,
            isNext: false,
            releasedEarly: false
        };

