import React, { useState, useEffect, useMemo } from 'react';
import { RefreshCw, ChevronUp, Plus, Search, LogOut } from 'lucide-react';
import { INITIAL_RESPAWNS } from './data/respawns';
import { Respawn, NewClaimData, Claim } from './types';
import RespawnCard from './components/RespawnCard';
import ClaimModal from './components/ClaimModal';
import RespawnSelector from './components/RespawnSelector';
import LoginPage from './components/LoginPage';
import { calculateEndTime } from './utils/time';

function App() {
  // --- Auth State ---
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [authChecking, setAuthChecking] = useState(true);

  // --- App Data State ---
  const [respawns, setRespawns] = useState<Respawn[]>(INITIAL_RESPAWNS);

  // Modal States
  const [claimModalOpen, setClaimModalOpen] = useState(false);
  const [selectorOpen, setSelectorOpen] = useState(false);

  const [activeRespawnId, setActiveRespawnId] = useState<string | null>(null);
  const [modalMode, setModalMode] = useState<'CLAIM' | 'NEXT'>('CLAIM');

  // --- Auth Effect ---
  useEffect(() => {
    const token = localStorage.getItem('x3t_auth_token');
    if (token) {
      setIsAuthenticated(true);
    }
    setAuthChecking(false);
  }, []);

  const handleLogin = (email: string) => {
    localStorage.setItem('x3t_auth_token', btoa(email)); // Simple mock token
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    localStorage.removeItem('x3t_auth_token');
    setIsAuthenticated(false);
  };

  // --- Derived Data ---

  // Main View: Only show OCCUPIED respawns
  const occupiedRespawns = respawns.filter(r => !!r.currentClaim);

  // Selector View: Only show FREE respawns
  const freeRespawns = respawns.filter(r => !r.currentClaim);

  // --- Handlers ---

  const handleOpenSelector = () => {
    setSelectorOpen(true);
  };

  const handleSelectFromList = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('CLAIM');
    setSelectorOpen(false); 
    setClaimModalOpen(true); 
  };

  const handleOpenClaim = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('CLAIM');
    setClaimModalOpen(true);
  };

  const handleOpenNext = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('NEXT');
    setClaimModalOpen(true);
  };

  const handleCloseModals = () => {
    setClaimModalOpen(false);
    setSelectorOpen(false);
    setActiveRespawnId(null);
  };

  const handleModalSubmit = (data: NewClaimData) => {
    if (!activeRespawnId) return;

    setRespawns(prev => prev.map(r => {
      if (r.id !== activeRespawnId) return r;

      const now = Date.now();

      if (modalMode === 'CLAIM') {
        const endTime = calculateEndTime(now, data.durationMinutes);
        const newClaim: Claim = {
          id: crypto.randomUUID(),
          playerName: data.playerName,
          startTime: now,
          durationMinutes: data.durationMinutes,
          endTime: endTime,
          isNext: false
        };
        return { ...r, currentClaim: newClaim };
      } 
      else {
        // NEXT Logic
        let lastEndTime = r.currentClaim ? r.currentClaim.endTime : now;
        if (r.nextQueue.length > 0) {
          lastEndTime = r.nextQueue[r.nextQueue.length - 1].endTime;
        }

        const endTime = calculateEndTime(lastEndTime, data.durationMinutes);

        const newNext: Claim = {
            id: crypto.randomUUID(),
            playerName: data.playerName,
            startTime: lastEndTime,
            durationMinutes: data.durationMinutes,
            endTime: endTime,
            isNext: true
        };

        return { ...r, nextQueue: [...r.nextQueue, newNext] };
      }
    }));
  };

  // Logic:
  // If no queue: Remove Current.
  // If queue exists: Mark Current as "releasedEarly" (Yellow state).
  // If cancelling a Next item: Remove from queue.
  const handleCancel = (respawnId: string, claimId: string, isNext: boolean) => {
    // REMOVED window.confirm to ensure instant feedback and avoid browser blocking issues.

    setRespawns(prev => {
        return prev.map(r => {
            if (r.id !== respawnId) return r;

            if (!isNext) {
                // --- CANCEL CURRENT CLAIM ---
                const hasQueue = r.nextQueue.length > 0;

                if (hasQueue) {
                    // Rule 1: Queue Exists -> Change to Yellow (Released)
                    // We DO NOT remove the claim yet, we just flag it.
                    if (!r.currentClaim) return r;
                    return { 
                        ...r, 
                        currentClaim: { ...r.currentClaim, releasedEarly: true } 
                    };
                } else {
                     // Rule 2: No Queue -> Remove Claim Immediately (Free)
                    return { ...r, currentClaim: null };
                }
            } else {
                // --- CANCEL NEXT ITEM ---
                const newQueue = r.nextQueue.filter(q => q.id !== claimId);

                // Recalculate times for the remaining queue
                let baseTime = r.currentClaim ? r.currentClaim.endTime : Date.now();
                const recalculatedQueue = newQueue.map(q => {
                    const qEnd = calculateEndTime(baseTime, q.durationMinutes);
                    const updated = { ...q, startTime: baseTime, endTime: qEnd };
                    baseTime = qEnd;
                    return updated;
                });

                return { ...r, nextQueue: recalculatedQueue };
            }
        });
    });
  };

  // New Logic: The Next person clicks "Anticipate" on a Yellow card
  // Updated Rule: Add residual time from previous claim to the new claim
  // Rule Check: Ensure total time does not exceed respawn limit (195m for special, 140m for normal)
  const handleAnticipate = (respawnId: string) => {
    setRespawns(prev => prev.map(r => {
        if (r.id !== respawnId) return r;
        if (r.nextQueue.length === 0) return r;

        const now = Date.now();

        // LIMIT DEFINITION
        // Special: 3h 15m = 195 minutes
        // Normal: 2h 20m = 140 minutes
        const MAX_ALLOWED_MINUTES = r.isSpecial ? 195 : 140;

        // 1. Calculate Bonus Time (Residual from previous player)
        let bonusMinutes = 0;
        if (r.currentClaim && r.currentClaim.endTime > now) {
            const diffMs = r.currentClaim.endTime - now;
            bonusMinutes = Math.floor(diffMs / (1000 * 60));
            // Safety check: avoid negative bonus if logic desyncs
            if (bonusMinutes < 0) bonusMinutes = 0;
        }

        // 2. Get next player and remaining queue
        const nextUp = r.nextQueue[0];
        const remainingQueue = r.nextQueue.slice(1);

        // 3. Create new Current Claim (Original Duration + Bonus)
        // CAP THE DURATION if it exceeds the limit
        let potentialDuration = nextUp.durationMinutes + bonusMinutes;
        if (potentialDuration > MAX_ALLOWED_MINUTES) {
          potentialDuration = MAX_ALLOWED_MINUTES;
        }

        const newEndTime = calculateEndTime(now, potentialDuration);

        const newCurrent: Claim = {
            ...nextUp,
            startTime: now,
            durationMinutes: potentialDuration, 
            endTime: newEndTime,
            isNext: false,
            releasedEarly: false
        };

        // 4. Recalculate remaining queue times based on newCurrent end time
        let previousEnd = newEndTime;
        const recalculatedQueue = remainingQueue.map(q => {
            const qEnd = calculateEndTime(previousEnd, q.durationMinutes);
            const updated = { ...q, startTime: previousEnd, endTime: qEnd };
            previousEnd = qEnd;
            return updated;
        });

        return { ...r, currentClaim: newCurrent, nextQueue: recalculatedQueue };
    }));
  };

  // Auto-remove expired claims every minute
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      setRespawns(prev => prev.map(r => {
        if (r.currentClaim && r.currentClaim.endTime <= now) {
          // Current expired. Move queue up.
          let newCurrent = null;
          let newQueue = [...r.nextQueue];

          if (newQueue.length > 0) {
            const nextUp = newQueue.shift();
            if (nextUp) {
               newCurrent = { ...nextUp, isNext: false };
            }
          }
          return { ...r, currentClaim: newCurrent, nextQueue: newQueue };
        }
        return r;
      }));
    }, 30000); // Check every 30s
    return () => clearInterval(interval);
  }, []);

  const activeRespawn = respawns.find(r => r.id === activeRespawnId) || null;

  // --- Render Logic ---

  if (authChecking) {
    return <div className="min-h-screen bg-[#0b1121]"></div>; // Loading flicker prevention
  }

  if (!isAuthenticated) {
    return <LoginPage onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-[#0b1121] pb-20 selection:bg-cyan-500/30">

      {/* Header */}
      <header className="bg-[#0f172a]/80 backdrop-blur-md border-b border-cyan-900/30 sticky top-0 z-40 shadow-[0_4px_20px_-5px_rgba(8,145,178,0.1)]">
        <div className="container mx-auto px-4 py-3 flex flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-4">
            {/* MAJOR Logo */}
            <div className="relative group shrink-0 hidden sm:block">
              <div className="absolute -inset-1 bg-gradient-to-r from-cyan-500 to-blue-600 rounded-lg blur opacity-40 group-hover:opacity-75 transition duration-200"></div>
              <div className="relative w-12 h-12 bg-[#0b1121] rounded-lg border border-cyan-800 flex flex-col items-center justify-center shadow-lg">
                 <ChevronUp size={28} className="text-cyan-400 -mb-2" strokeWidth={3} />
                 <span className="text-[10px] font-bold text-cyan-500 tracking-wider">MJR</span>
              </div>
            </div>

            <div>
              <h1 className="text-2xl sm:text-3xl font-bold text-white tracking-wider digital-font drop-shadow-[0_0_10px_rgba(34,211,238,0.3)]">
                CLAIMED
              </h1>
              <div className="flex items-center gap-2">
                <div className="h-[2px] w-4 bg-cyan-500 rounded-full"></div>
                <p className="text-[10px] text-cyan-400/80 tracking-[0.2em] uppercase font-bold">Live Monitor</p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-3">
            {/* Logout Button */}
            <button
                onClick={handleLogout}
                className="p-3 text-slate-400 hover:text-white hover:bg-slate-800 rounded-lg transition-colors"
                title="Sair / Logout"
            >
                <LogOut size={20} />
            </button>

            {/* New Claim Action Button */}
            <button 
                onClick={handleOpenSelector}
                className="group relative inline-flex items-center justify-center gap-2 px-6 py-3 font-bold text-white transition-all duration-200 bg-cyan-600 font-lg rounded-lg hover:bg-cyan-500 hover:shadow-[0_0_20px_rgba(8,145,178,0.4)] focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-cyan-600 focus:ring-offset-slate-900"
            >
                <span className="absolute inset-0 w-full h-full -mt-1 rounded-lg opacity-30 bg-gradient-to-b from-transparent via-transparent to-black"></span>
                <Plus size={20} className="relative group-hover:rotate-90 transition-transform" strokeWidth={3} />
                <span className="relative uppercase tracking-widest text-sm hidden sm:inline">Novo Claim</span>
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-4 py-8">

        {/* Info Bar */}
        <div className="flex justify-between items-center mb-6 bg-[#1e293b]/30 p-4 rounded-md border-l-4 border-cyan-500 backdrop-blur-sm shadow-lg">
           <div className="text-xs text-cyan-600/80 flex items-center gap-2 uppercase tracking-wider font-bold">
             <RefreshCw size={12} className="animate-spin-slow" /> 
             System Active
           </div>
           <div className="text-xs font-bold uppercase tracking-wider text-slate-400">
              Occupied Spots: <span className="text-white">{occupiedRespawns.length}</span>
           </div>
        </div>

        {/* Occupied Grid */}
        {occupiedRespawns.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {occupiedRespawns.map(respawn => (
              <RespawnCard 
                key={respawn.id} 
                respawn={respawn}
                onClaim={handleOpenClaim} // Won't be used since card is occupied
                onNext={handleOpenNext}
                onCancel={handleCancel}
                onAnticipate={handleAnticipate}
              />
            ))}
          </div>
        ) : (
          <div className="text-center py-24 text-slate-600 border border-dashed border-slate-800 rounded-xl bg-slate-900/20">
             <div className="inline-block p-4 rounded-full bg-slate-900/50 mb-4 shadow-inner">
               <Search size={32} className="opacity-50" />
             </div>
             <p className="text-lg font-medium text-slate-400">NO ACTIVE CLAIMS</p>
             <p className="text-xs uppercase tracking-widest text-slate-600 mt-1 mb-6">All hunting grounds are currently free.</p>

             <button 
                onClick={handleOpenSelector}
                className="inline-flex items-center gap-2 text-cyan-400 hover:text-cyan-300 border border-cyan-900/50 hover:border-cyan-500/50 px-6 py-2 rounded uppercase font-bold text-xs tracking-widest transition-all"
             >
               <Plus size={14} /> Start a Session
             </button>
          </div>
        )}
      </main>

      {/* Modals */}
      <ClaimModal 
        isOpen={claimModalOpen}
        onClose={handleCloseModals}
        onSubmit={handleModalSubmit}
        respawn={activeRespawn}
        mode={modalMode}
      />

      <RespawnSelector 
        isOpen={selectorOpen}
        onClose={() => setSelectorOpen(false)}
        respawns={freeRespawns}
        onSelect={handleSelectFromList}
      />

    </div>
  );
}

