    await supabase.from('claims').delete().eq('id', oldClaim.id);

    // 2. Update Next claim to be Current
    await supabase.from('claims').update({
        is_next: false,
        start_time: now,
        duration_minutes: potentialDuration,
        end_time: newEndTime,
        released_early: false
    }).eq('id', nextUp.id);

    // 3. Update subsequent queue items? 
    // This is complex to do in one batch without backend function. 
    // Realtime will catch the first two updates. 
    // The "Queue Gap" will technically exist in DB timestamps but visual UI might show gaps.
    // For this version, we accept the time gap until the next user claims or we implement a loop.

    // Loop to update remaining queue times
    let prevEnd = newEndTime;
    const remainingQueue = respawn.nextQueue.slice(1);
    for (const q of remainingQueue) {
        const qEnd = calculateEndTime(prevEnd, q.durationMinutes);
        await supabase.from('claims').update({
            start_time: prevEnd,
            end_time: qEnd
        }).eq('id', q.id);
        prevEnd = qEnd;
    }
  };

  // --- Render Logic ---

  if (authChecking) {
    return <div className="min-h-screen bg-[#0b1121] flex items-center justify-center"><RefreshCw className="animate-spin text-cyan-500" /></div>;
  }

  if (!isAuthenticated) {
    return <LoginPage onLogin={() => setIsAuthenticated(true)} />;
