import React, { useState, useEffect, useMemo } from 'react';
import { RefreshCw, ChevronUp, Plus, Search, LogOut } from 'lucide-react';
import { INITIAL_RESPAWNS } from './data/respawns';
import { Respawn, NewClaimData, Claim } from './types';
import RespawnCard from './components/RespawnCard';
import ClaimModal from './components/ClaimModal';
import RespawnSelector from './components/RespawnSelector';
import LoginPage from './components/LoginPage';
import { calculateEndTime } from './utils/time';
import { supabase } from './utils/supabaseClient';

function App() {
  // --- Auth State ---
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [authChecking, setAuthChecking] = useState(true);
  const [userId, setUserId] = useState<string | null>(null);

  // --- App Data State ---
  const [claims, setClaims] = useState<any[]>([]); // Storing raw DB claims to map locally
  const [loadingClaims, setLoadingClaims] = useState(false);

  // Modal States
  const [claimModalOpen, setClaimModalOpen] = useState(false);
  const [selectorOpen, setSelectorOpen] = useState(false);

  const [activeRespawnId, setActiveRespawnId] = useState<string | null>(null);
  const [modalMode, setModalMode] = useState<'CLAIM' | 'NEXT'>('CLAIM');

  // --- Auth Effect ---
  useEffect(() => {
    const checkSession = async () => {
        const { data: { session } } = await supabase.auth.getSession();
        if (session) {
            setIsAuthenticated(true);
            setUserId(session.user.id);
            fetchClaims();
        }
        setAuthChecking(false);
    };

    checkSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
        if (session) {
            setIsAuthenticated(true);
            setUserId(session.user.id);
            fetchClaims();
        } else {
            setIsAuthenticated(false);
            setUserId(null);
            setClaims([]);
        }
    });

    return () => subscription.unsubscribe();
  }, []);

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  const fetchClaims = async () => {
    // Only show loading indicator on first load or if list is empty
    if (claims.length === 0) setLoadingClaims(true);

    const { data, error } = await supabase
        .from('claims')
        .select('*');

    if (!error && data) {
        setClaims(data);
    }
    setLoadingClaims(false);
  };

  // --- Realtime Subscription ---
  useEffect(() => {
    if (!isAuthenticated) return;

    const channel = supabase
      .channel('schema-db-changes')
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'claims',
        },
        () => {
            fetchClaims();
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [isAuthenticated]);


  // --- Derived Data (Merge Initial Respawns with DB Claims) ---
  const derivedRespawns: Respawn[] = useMemo(() => {
    // Group claims by respawn_id
    const claimsByRespawn: Record<string, Claim[]> = {};

    claims.forEach((c: any) => {
        if (!c.respawn_id) return;

        // Map DB snake_case to App camelCase
        const mappedClaim: Claim = {
            id: c.id,
            userId: c.user_id, // Map database column to Typescript interface
            playerName: c.player_name,
            startTime: Number(c.start_time),
            durationMinutes: Number(c.duration_minutes),
            endTime: Number(c.end_time),
            isNext: c.is_next,
            releasedEarly: c.released_early
        };

        if (!claimsByRespawn[c.respawn_id]) claimsByRespawn[c.respawn_id] = [];
        claimsByRespawn[c.respawn_id].push(mappedClaim);
    });

    return INITIAL_RESPAWNS.map(r => {
        const myClaims = claimsByRespawn[r.id] || [];

        // Logic: The "Current" claim is the active one (not isNext).
        // If there are multiple (shouldn't happen with logic), take earliest start.
        const current = myClaims.find(c => !c.isNext);

        // Queue: All isNext=true, sorted by end time (approx FIFO)
        const queue = myClaims
            .filter(c => c.isNext)
            .sort((a, b) => a.endTime - b.endTime);

        return {
            ...r,
            currentClaim: current || null,
            nextQueue: queue
        };
    });
  }, [claims]);


  // Main View: Only show OCCUPIED respawns
  const occupiedRespawns = derivedRespawns.filter(r => !!r.currentClaim);
  // Selector View: Only show FREE respawns
  const freeRespawns = derivedRespawns.filter(r => !r.currentClaim);

  // Calculate active respawn for modals
  const activeRespawn = useMemo(() => 
    derivedRespawns.find(r => r.id === activeRespawnId) || null, 
    [derivedRespawns, activeRespawnId]
  );

  // --- Handlers ---

  const handleOpenSelector = () => setSelectorOpen(true);

  const handleSelectFromList = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('CLAIM');
    setSelectorOpen(false); 
    setClaimModalOpen(true); 
  };

  const handleOpenClaim = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('CLAIM');
    setClaimModalOpen(true);
  };

  const handleOpenNext = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('NEXT');
    setClaimModalOpen(true);
  };

  const handleCloseModals = () => {
    setClaimModalOpen(false);
    setSelectorOpen(false);
    setActiveRespawnId(null);
  };

  const handleModalSubmit = async (data: NewClaimData) => {
    if (!activeRespawnId || !userId) return;

    // We can use the memoized activeRespawn, but we need to check if it's still valid
    if (!activeRespawn) return;

    const now = Date.now();
    let startTime = now;
    let isNext = false;

    if (modalMode === 'NEXT') {
        isNext = true;
        // Calculate start time based on end of queue
        let lastEndTime = activeRespawn.currentClaim ? activeRespawn.currentClaim.endTime : now;
        if (activeRespawn.nextQueue.length > 0) {
          lastEndTime = activeRespawn.nextQueue[activeRespawn.nextQueue.length - 1].endTime;
        }
        startTime = lastEndTime;
    }

    const endTime = calculateEndTime(startTime, data.durationMinutes);

    // DB Insert
    const { error } = await supabase.from('claims').insert({
        respawn_id: activeRespawnId,
        user_id: userId,
        player_name: data.playerName,
        start_time: startTime,
        duration_minutes: data.durationMinutes,
        end_time: endTime,
        is_next: isNext,
        released_early: false
    });

    if (error) {
        alert("Erro ao agendar: " + error.message);
    }
  };

  const handleCancel = async (respawnId: string, claimId: string, isNext: boolean) => {
    // RLS in Supabase prevents deleting others' claims.
    // Logic here mirrors what the user intends.

    if (isNext) {
        // Just delete from queue
        await supabase.from('claims').delete().eq('id', claimId);
    } else {
        // Current Claim
        const respawn = derivedRespawns.find(r => r.id === respawnId);
        if (respawn && respawn.nextQueue.length > 0) {
            // If queue exists, mark as released (Yellow State)
             await supabase.from('claims').update({ released_early: true }).eq('id', claimId);
        } else {
            // No queue, just free the spot
            await supabase.from('claims').delete().eq('id', claimId);
        }
    }
  };

  const handleAnticipate = async (respawnId: string) => {
    const respawn = derivedRespawns.find(r => r.id === respawnId);
    if (!respawn || !respawn.currentClaim || respawn.nextQueue.length === 0) return;

    const oldClaim = respawn.currentClaim;
    const nextUp = respawn.nextQueue[0];

    const now = Date.now();
    const MAX_ALLOWED_MINUTES = respawn.isSpecial ? 195 : 140;

    // Calculate bonus time if previous user left early (visual only mostly, but good for data)
    let bonusMinutes = 0;
    if (oldClaim.endTime > now) {
        const diffMs = oldClaim.endTime - now;
        bonusMinutes = Math.floor(diffMs / (1000 * 60));
        if (bonusMinutes < 0) bonusMinutes = 0;
    }

    let potentialDuration = nextUp.durationMinutes + bonusMinutes;
    if (potentialDuration > MAX_ALLOWED_MINUTES) {
        potentialDuration = MAX_ALLOWED_MINUTES;
    }
    const newEndTime = calculateEndTime(now, potentialDuration);

    // 1. Delete old claim
    await supabase.from('claims').delete().eq('id', oldClaim.id);

    // 2. Promote Next claim
    await supabase.from('claims').update({
        is_next: false,
        start_time: now,
        duration_minutes: potentialDuration,
        end_time: newEndTime,
        released_early: false
    }).eq('id', nextUp.id);

    // 3. Update subsequent queue times
    let prevEnd = newEndTime;
    const remainingQueue = respawn.nextQueue.slice(1);
    for (const q of remainingQueue) {
        const qEnd = calculateEndTime(prevEnd, q.durationMinutes);
        await supabase.from('claims').update({
            start_time: prevEnd,
            end_time: qEnd
        }).eq('id', q.id);
        prevEnd = qEnd;
    }
  };

  if (authChecking) {
    return <div className="min-h-screen bg-[#0b1121] flex items-center justify-center"><RefreshCw className="animate-spin text-cyan-500" /></div>;
  }

  if (!isAuthenticated) {
    return <LoginPage onLogin={() => setIsAuthenticated(true)} />;
  }

  return (
    <div className="min-h-screen bg-[#0b1121] pb-20 selection:bg-cyan-500/30">

      {/* Header */}
      <header className="bg-[#0f172a]/80 backdrop-blur-md border-b border-cyan-900/30 sticky top-0 z-40 shadow-[0_4px_20px_-5px_rgba(8,145,178,0.1)]">
        <div className="container mx-auto px-4 py-3 flex flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-4">
            <div className="relative group shrink-0 hidden sm:block">
              <div className="absolute -inset-1 bg-gradient-to-r from-cyan-500 to-blue-600 rounded-lg blur opacity-40 group-hover:opacity-75 transition duration-200"></div>
              <div className="relative w-12 h-12 bg-[#0b1121] rounded-lg border border-cyan-800 flex flex-col items-center justify-center shadow-lg">
                 <ChevronUp size={28} className="text-cyan-400 -mb-2" strokeWidth={3} />
                 <span className="text-[10px] font-bold text-cyan-500 tracking-wider">MJR</span>
              </div>
            </div>

            <div>
              <h1 className="text-2xl sm:text-3xl font-bold text-white tracking-wider digital-font drop-shadow-[0_0_10px_rgba(34,211,238,0.3)]">
                CLAIMED
              </h1>
              <div className="flex items-center gap-2">
                <div className="h-[2px] w-4 bg-cyan-500 rounded-full"></div>
                <p className="text-[10px] text-cyan-400/80 tracking-[0.2em] uppercase font-bold">Live Monitor</p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <button
                onClick={handleLogout}
                className="p-3 text-slate-400 hover:text-white hover:bg-slate-800 rounded-lg transition-colors"
                title="Sair / Logout"
            >
                <LogOut size={20} />
            </button>

            <button 
                onClick={handleOpenSelector}
                className="group relative inline-flex items-center justify-center gap-2 px-6 py-3 font-bold text-white transition-all duration-200 bg-cyan-600 font-lg rounded-lg hover:bg-cyan-500 hover:shadow-[0_0_20px_rgba(8,145,178,0.4)] focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-cyan-600 focus:ring-offset-slate-900"
            >
                <span className="absolute inset-0 w-full h-full -mt-1 rounded-lg opacity-30 bg-gradient-to-b from-transparent via-transparent to-black"></span>
                <Plus size={20} className="relative group-hover:rotate-90 transition-transform" strokeWidth={3} />
                <span className="relative uppercase tracking-widest text-sm hidden sm:inline">Novo Claim</span>
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-4 py-8">

        {/* Info Bar */}
        <div className="flex justify-between items-center mb-6 bg-[#1e293b]/30 p-4 rounded-md border-l-4 border-cyan-500 backdrop-blur-sm shadow-lg">
           <div className="text-xs text-cyan-600/80 flex items-center gap-2 uppercase tracking-wider font-bold">
             <RefreshCw size={12} className={`animate-spin-slow ${loadingClaims ? 'text-white' : ''}`} /> 
             {loadingClaims ? 'Syncing...' : 'System Active'}
           </div>
           <div className="text-xs font-bold uppercase tracking-wider text-slate-400">
              Occupied Spots: <span className="text-white">{occupiedRespawns.length}</span>
           </div>
        </div>

        {/* Occupied Grid */}
        {occupiedRespawns.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {occupiedRespawns.map(respawn => (
              <RespawnCard 
                key={respawn.id} 
                respawn={respawn}
                currentUserId={userId}
                onClaim={handleOpenClaim} 
                onNext={handleOpenNext}
                onCancel={handleCancel}
                onAnticipate={handleAnticipate}
              />
            ))}
          </div>
        ) : (
          <div className="text-center py-24 text-slate-600 border border-dashed border-slate-800 rounded-xl bg-slate-900/20">
             <div className="inline-block p-4 rounded-full bg-slate-900/50 mb-4 shadow-inner">
               <Search size={32} className="opacity-50" />
             </div>
             <p className="text-lg font-medium text-slate-400">NO ACTIVE CLAIMS</p>
             <p className="text-xs uppercase tracking-widest text-slate-600 mt-1 mb-6">All hunting grounds are currently free.</p>

             <button 
                onClick={handleOpenSelector}
                className="inline-flex items-center gap-2 text-cyan-400 hover:text-cyan-300 border border-cyan-900/50 hover:border-cyan-500/50 px-6 py-2 rounded uppercase font-bold text-xs tracking-widest transition-all"
             >
               <Plus size={14} /> Start a Session
             </button>
          </div>
        )}
      </main>

      {/* Modals */}
      <ClaimModal 
        isOpen={claimModalOpen}
        onClose={handleCloseModals}
        onSubmit={handleModalSubmit}
        respawn={activeRespawn}
        mode={modalMode}
      />

      <RespawnSelector 
        isOpen={selectorOpen}
        onClose={() => setSelectorOpen(false)}
        respawns={freeRespawns}
        onSelect={handleSelectFromList}
      />

    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { X, Clock, User, CheckCircle } from 'lucide-react';
import { NewClaimData, Respawn } from '../types';

interface ClaimModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (data: NewClaimData) => void;
  respawn: Respawn | null;
  mode: 'CLAIM' | 'NEXT';
}

const ClaimModal: React.FC<ClaimModalProps> = ({ isOpen, onClose, onSubmit, respawn, mode }) => {
  const [playerName, setPlayerName] = useState('');
  const [duration, setDuration] = useState(60); // Default 1 hour
  const [error, setError] = useState('');

  // Reset state when modal opens
  useEffect(() => {
    if (isOpen) {
      setPlayerName('');
      setDuration(60);
      setError('');
    }
  }, [isOpen]);

  if (!isOpen || !respawn) return null;

  // Constraints
  const MIN_MINUTES = 30;
  // Special: 3h 15m (195m)
  // Others: 2h 20m (140m)
  const MAX_MINUTES = respawn.isSpecial ? 195 : 140; 
  const MAX_DISPLAY = respawn.isSpecial ? "3h 15m" : "2h 20m";

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!playerName.trim()) {
      setError('Nome do personagem é obrigatório.');
      return;
    }
    if (duration < MIN_MINUTES || duration > MAX_MINUTES) {
      setError(`A duração deve ser entre 30 min e ${MAX_DISPLAY}.`);
      return;
    }
    onSubmit({ playerName, durationMinutes: duration });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-[#050b14]/80 backdrop-blur-sm p-4">
      <div className="bg-[#0f172a] border border-cyan-500/30 rounded shadow-[0_0_40px_-10px_rgba(8,145,178,0.3)] w-full max-w-md animate-in fade-in zoom-in duration-200 relative overflow-hidden">

        {/* Top Accent Line */}
        <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-cyan-600 to-blue-600"></div>

        <div className="flex justify-between items-center p-5 border-b border-slate-800 bg-slate-900/50">
          <div>
             <h3 className="text-xl font-bold text-white digital-font tracking-wider">
                {mode === 'CLAIM' ? 'AGENDAR HORÁRIO' : 'ENTRAR NA FILA'}
             </h3>
             <p className="text-[10px] text-cyan-500 uppercase tracking-widest font-bold">Protocolo: {mode === 'CLAIM' ? 'AGENDAMENTO' : 'NEXT'}</p>
          </div>
          <button onClick={onClose} className="text-slate-500 hover:text-cyan-400 transition-colors bg-slate-800/50 p-1.5 rounded-full hover:bg-slate-800">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          <div className="space-y-1 pb-2 border-b border-slate-800 border-dashed">
            <h4 className="text-lg font-bold text-cyan-100">{respawn.name}</h4>
            <span className="text-xs font-mono text-slate-500 uppercase tracking-widest">{respawn.category}</span>
          </div>

          <div className="space-y-5">
            {/* Player Name */}
            <div>
              <label className="block text-xs font-bold text-slate-400 mb-1.5 uppercase tracking-wide flex items-center gap-2">
                <User size={14} className="text-cyan-500" /> Nome do Personagem
              </label>
              <input
                type="text"
                value={playerName}
                onChange={(e) => setPlayerName(e.target.value)}
                placeholder="DIGITE O NOME..."
                className="w-full bg-[#0b1121] border border-slate-700 rounded px-4 py-2.5 text-white placeholder-slate-600 focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 outline-none transition-all font-medium"
                autoFocus
              />
            </div>

            {/* Duration */}
            <div>
              <label className="block text-xs font-bold text-slate-400 mb-1.5 uppercase tracking-wide flex items-center gap-2">
                <Clock size={14} className="text-cyan-500" /> Tempo de Hunt
              </label>
              <div className="flex items-center gap-4 bg-[#0b1121] p-3 rounded border border-slate-700">
                <input
                  type="range"
                  min={MIN_MINUTES}
                  max={MAX_MINUTES}
                  step={5}
                  value={duration}
                  onChange={(e) => setDuration(Number(e.target.value))}
                  className="flex-grow h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-cyan-500"
                />
                <div className="flex items-center bg-slate-800 rounded px-2 py-1 border border-slate-700 w-24 justify-center">
                    <span className="text-cyan-300 font-mono text-lg font-bold">{duration}</span>
                    <span className="text-xs text-slate-500 ml-1">min</span>
                </div>
              </div>
              <div className="flex justify-between mt-2 text-[10px] text-slate-500 font-mono">
                <span>MIN: 30m</span>
                <span className="text-cyan-600">MAX: {Math.floor(MAX_MINUTES/60)}h {MAX_MINUTES%60}m</span>
              </div>
            </div>
          </div>

          {error && (
            <div className="p-3 bg-rose-950/30 border-l-2 border-rose-500 text-rose-200 text-xs font-medium">
              ! {error}
            </div>
          )}

          <div className="flex gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 py-2.5 text-slate-400 hover:text-white border border-slate-700 hover:border-slate-500 rounded text-sm font-bold uppercase tracking-wide transition-colors"
            >
              Cancelar
            </button>
            <button
              type="submit"
              className="flex-[2] bg-gradient-to-r from-cyan-700 to-blue-600 hover:from-cyan-600 hover:to-blue-500 text-white text-sm font-bold uppercase tracking-wide py-2.5 rounded shadow-lg shadow-cyan-900/20 transition-all flex justify-center items-center gap-2"
            >
              <CheckCircle size={16} /> Confirmar
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

