import React, { useState, useEffect } from 'react';
import { Shield, Clock, Trash2, ArrowRight, Plus, Activity, PlayCircle } from 'lucide-react';
import { Respawn } from '../types';
import { formatTimeRemaining, formatEndTime } from '../utils/time';

interface RespawnCardProps {
  respawn: Respawn;
  currentUserId: string | null;
  onClaim: (respawnId: string) => void;
  onNext: (respawnId: string) => void;
  onCancel: (respawnId: string, claimId: string, isNext: boolean) => void;
  onAnticipate?: (respawnId: string) => void;
}

const RespawnCard: React.FC<RespawnCardProps> = ({ respawn, currentUserId, onClaim, onNext, onCancel, onAnticipate }) => {
  const [timeLeft, setTimeLeft] = useState<string>('');

  // Update timer every minute
  useEffect(() => {
    const updateTimer = () => {
      if (respawn.currentClaim) {
        setTimeLeft(formatTimeRemaining(respawn.currentClaim.endTime));
      } else {
        setTimeLeft('');
      }
    };

    updateTimer();
    const interval = setInterval(updateTimer, 60000); // Update every minute
    return () => clearInterval(interval);
  }, [respawn.currentClaim]);

  const isOccupied = !!respawn.currentClaim;
  const isReleased = respawn.currentClaim?.releasedEarly || false;

  // Dynamic styles based on state
  let containerBorder = 'border-cyan-900/30 hover:border-cyan-500/50';
  let containerBg = 'bg-gradient-to-b from-[#0f172a] to-[#0f172a]';
  let statusColor = 'text-emerald-400';
  let headerBg = 'bg-cyan-950/10';
  let statusText = "LIVRE";

  if (isOccupied) {
    if (isReleased) {
        // YELLOW / AMBER STATE
        containerBorder = 'border-amber-600/50 hover:border-amber-500/60';
        containerBg = 'bg-gradient-to-b from-[#1a1505] to-[#0f172a]';
        statusColor = 'text-amber-400';
        headerBg = 'bg-amber-950/20';
        statusText = "ABERTO PARA NEXT";
    } else {
        // RED STATE
        containerBorder = 'border-rose-900/50 hover:border-rose-700/50';
        containerBg = 'bg-gradient-to-b from-[#1a1115] to-[#0f172a]';
        statusColor = 'text-rose-500';
        headerBg = 'bg-rose-950/20';
        statusText = "OCUPADO";
    }
  }

  return (
    <div className={`relative border rounded bg-slate-900 overflow-hidden transition-all duration-300 group ${containerBorder} ${containerBg}`}>

      {/* Decorative corner accent */}
      {!isOccupied && <div className="absolute top-0 right-0 w-16 h-16 bg-gradient-to-bl from-cyan-500/10 to-transparent -mr-8 -mt-8 rounded-full blur-xl group-hover:from-cyan-400/20 transition-all"></div>}

      {/* Header */}
      <div className={`p-3 border-b border-slate-800 flex justify-between items-start ${headerBg}`}>
        <div className="z-10">
          <h4 className="font-bold text-slate-100 flex items-center gap-2 digital-font tracking-wide text-lg">
             {respawn.name}
             {respawn.tier > 1 && <span className="text-[9px] bg-slate-800 text-cyan-300 px-1.5 py-0.5 rounded border border-cyan-900 font-mono">T{respawn.tier}</span>}
          </h4>
          <div className="flex items-center gap-2 mt-0.5">
            <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{respawn.category}</span>
            {respawn.isSpecial && <span className="text-[9px] text-purple-400 font-bold uppercase tracking-wider border border-purple-900/50 px-1 rounded bg-purple-900/10">Special</span>}
          </div>
        </div>

        <div className={`flex items-center gap-1.5 ${statusColor} bg-slate-950/50 px-2 py-1 rounded border border-slate-800 shadow-inner`}>
          <Activity size={14} className={isOccupied ? "" : "animate-pulse"} />
          <span className="text-[10px] font-bold uppercase tracking-wider">{statusText}</span>
        </div>
      </div>

      {/* Body */}
      <div className="p-4 space-y-4">
        {isOccupied && respawn.currentClaim ? (
          <div className={`rounded border-l-2 p-3 shadow-lg relative overflow-hidden group/card ${isReleased ? 'bg-[#1a1205] border-amber-500' : 'bg-[#0b1121] border-rose-500'}`}>
            {/* Background pattern */}
            <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-20 pointer-events-none"></div>

            <div className="relative z-10 pl-1">
                {/* Header Row: Name & Trash Button via Flexbox (Safe Layout) */}
                <div className="flex justify-between items-start mb-2">
                    <span className={`font-bold truncate text-sm tracking-wide mr-2 mt-0.5 ${isReleased ? 'text-amber-100 line-through opacity-70' : 'text-rose-100'}`}>
                        {respawn.currentClaim.playerName}
                    </span>

                    {!isReleased && respawn.currentClaim.userId === currentUserId && (
                        <button 
                            type="button"
                            onClick={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                                onCancel(respawn.id, respawn.currentClaim!.id, false);
                            }}
                            className="text-slate-400 hover:text-rose-500 hover:bg-rose-950/80 bg-slate-900/50 transition-all p-1.5 rounded cursor-pointer z-50 border border-transparent hover:border-rose-500/50 -mt-1 -mr-1"
                            title="Desmarcar / Sair da Hunt"
                        >
                            <Trash2 size={16} />
                        </button>
                    )}
                </div>

                {isReleased && (
                    <div className="text-[10px] font-bold text-amber-500 uppercase tracking-widest mb-2 flex items-center gap-1">
                        <span className="w-1.5 h-1.5 rounded-full bg-amber-500 animate-pulse"></span>
                        Vaga Disponível
                    </div>
                )}

                <div className="flex justify-between items-end text-xs mt-3">
                    <div className="flex flex-col">
                        <span className="text-slate-500 text-[10px] uppercase font-bold">Tempo Restante</span>
                        <span className={`font-mono text-lg leading-none ${isReleased ? 'text-amber-400' : 'text-rose-400'}`}>{timeLeft}</span>
                    </div>
                    <div className="flex flex-col items-end">
                        <span className="text-slate-500 text-[10px] uppercase font-bold">Término</span>
                        <span className="text-slate-300 font-mono">{formatEndTime(respawn.currentClaim.endTime)}</span>
                    </div>
                </div>
            </div>
          </div>
        ) : (
          <div className="h-20 flex flex-col items-center justify-center text-slate-700 border border-dashed border-slate-800 rounded bg-slate-900/30">
            <span className="text-sm font-medium">Sistema Pronto</span>
            <span className="text-[10px] uppercase tracking-widest opacity-60">Aguardando ação</span>
          </div>
        )}

        {/* Next Queue */}
        {respawn.nextQueue.length > 0 && (
          <div className="space-y-2 mt-3 pt-3 border-t border-slate-800/50">
            <div className="flex items-center gap-2 text-[10px] text-cyan-600 font-bold uppercase tracking-widest">
              <ArrowRight size={10} /> Fila de Espera ({respawn.nextQueue.length})
            </div>
            <div className="space-y-1.5">
                {respawn.nextQueue.map((next, index) => (
                <div key={next.id} className="bg-slate-800/40 rounded px-2 py-1.5 text-xs border border-slate-700/50 flex justify-between items-center group/item hover:border-slate-600 transition-colors">
                    <div className="flex items-center gap-2 overflow-hidden">
                        <span className="text-cyan-700 font-mono text-[10px]">{String(index + 1).padStart(2, '0')}</span>
                        <span className="text-slate-300 truncate max-w-[100px] font-medium">{next.playerName}</span>
                    </div>
                    <div className="flex items-center gap-3">
                        <span className="text-slate-500 font-mono text-[10px] bg-slate-900 px-1 rounded">{Math.floor(next.durationMinutes / 60)}h{next.durationMinutes % 60 > 0 ? `${next.durationMinutes % 60}m` : ''}</span>

                        {next.userId === currentUserId && (
                          <button 
                              type="button"
                              onClick={(e) => {
                                  e.stopPropagation();
                                  onCancel(respawn.id, next.id, true);
                              }}
                              className="text-slate-600 hover:text-rose-400 p-1 cursor-pointer"
                          >
                              <XIcon size={12} />
                          </button>
                        )}
                    </div>
                </div>
                ))}
            </div>
          </div>
        )}
      </div>

      {/* Footer Actions */}
      <div className="p-2 bg-slate-950/30 border-t border-slate-800/50">
        {!isOccupied ? (
          <button 
            type="button"
            onClick={() => onClaim(respawn.id)}
            className="w-full bg-cyan-600 hover:bg-cyan-500 text-white text-xs font-bold uppercase tracking-wider py-2 rounded shadow-[0_0_10px_rgba(8,145,178,0.2)] hover:shadow-[0_0_15px_rgba(34,211,238,0.4)] transition-all flex justify-center items-center gap-2 group/btn"
          >
            <Shield size={14} className="group-hover/btn:scale-110 transition-transform" /> Marcar Respawn
          </button>
        ) : (
          <>
            {/* If released early and queue exists, show Anticipate Button */}
            {isReleased && respawn.nextQueue.length > 0 && onAnticipate ? (
                 <button 
                 type="button"
                 onClick={() => onAnticipate(respawn.id)}
                 className="w-full bg-amber-600 hover:bg-amber-500 text-white text-xs font-bold uppercase tracking-wider py-2 rounded shadow-[0_0_10px_rgba(245,158,11,0.2)] animate-pulse hover:animate-none transition-all flex justify-center items-center gap-2"
               >
                 <PlayCircle size={14} /> Antecipar / Iniciar
               </button>
            ) : (
                <button 
                type="button"
                onClick={() => onNext(respawn.id)}
                className="w-full bg-slate-800 hover:bg-slate-700 text-cyan-400 hover:text-cyan-300 border border-slate-700 hover:border-cyan-500/30 text-xs font-bold uppercase tracking-wider py-2 rounded transition-all flex justify-center items-center gap-2"
              >
                <Plus size={14} /> Entrar de Next
              </button>
            )}
          </>
        )}
      </div>
    </div>
  );
};

// Helper for the small X icon inside queue
const XIcon = ({ size }: { size: number }) => (
  <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 18 18"/></svg>
);

export default RespawnCard;

import React, { useState, useEffect, useMemo } from 'react';
import { RefreshCw, ChevronUp, Plus, Search, LogOut } from 'lucide-react';
import { INITIAL_RESPAWNS } from './data/respawns';
import { Respawn, NewClaimData, Claim } from './types';
import RespawnCard from './components/RespawnCard';
import ClaimModal from './components/ClaimModal';
import RespawnSelector from './components/RespawnSelector';
import LoginPage from './components/LoginPage';
import { calculateEndTime } from './utils/time';
import { supabase } from './utils/supabaseClient';

function App() {
  // --- Auth State ---
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [authChecking, setAuthChecking] = useState(true);
  const [userId, setUserId] = useState<string | null>(null);

  // --- App Data State ---
  const [claims, setClaims] = useState<any[]>([]); // Storing raw DB claims to map locally
  const [loadingClaims, setLoadingClaims] = useState(false);

  // Modal States
  const [claimModalOpen, setClaimModalOpen] = useState(false);
  const [selectorOpen, setSelectorOpen] = useState(false);

  const [activeRespawnId, setActiveRespawnId] = useState<string | null>(null);
  const [modalMode, setModalMode] = useState<'CLAIM' | 'NEXT'>('CLAIM');

  // --- Auth Effect ---
  useEffect(() => {
    const checkSession = async () => {
        const { data: { session } } = await supabase.auth.getSession();
        if (session) {
            setIsAuthenticated(true);
            setUserId(session.user.id);
            fetchClaims();
        }
        setAuthChecking(false);
    };

    checkSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
        if (session) {
            setIsAuthenticated(true);
            setUserId(session.user.id);
            fetchClaims();
        } else {
            setIsAuthenticated(false);
            setUserId(null);
            setClaims([]);
        }
    });

    return () => subscription.unsubscribe();
  }, []);

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  const fetchClaims = async () => {
    // Only show loading indicator on first load or if list is empty
    if (claims.length === 0) setLoadingClaims(true);

    const { data, error } = await supabase
        .from('claims')
        .select('*');

    if (!error && data) {
        setClaims(data);
    }
    setLoadingClaims(false);
  };

  // --- Realtime Subscription ---
  useEffect(() => {
    if (!isAuthenticated) return;

    const channel = supabase
      .channel('schema-db-changes')
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'claims',
        },
        () => {
            fetchClaims();
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [isAuthenticated]);


  // --- Derived Data (Merge Initial Respawns with DB Claims) ---
  const derivedRespawns: Respawn[] = useMemo(() => {
    // Group claims by respawn_id
    const claimsByRespawn: Record<string, Claim[]> = {};

    claims.forEach((c: any) => {
        if (!c.respawn_id) return;

        // Map DB snake_case to App camelCase
        const mappedClaim: Claim = {
            id: c.id,
            userId: c.user_id, // Map database column to Typescript interface
            playerName: c.player_name,
            startTime: Number(c.start_time),
            durationMinutes: Number(c.duration_minutes),
            endTime: Number(c.end_time),
            isNext: c.is_next,
            releasedEarly: c.released_early
        };

        if (!claimsByRespawn[c.respawn_id]) claimsByRespawn[c.respawn_id] = [];
        claimsByRespawn[c.respawn_id].push(mappedClaim);
    });

    return INITIAL_RESPAWNS.map(r => {
        const myClaims = claimsByRespawn[r.id] || [];

        // Logic: The "Current" claim is the active one (not isNext).
        // If there are multiple (shouldn't happen with logic), take earliest start.
        const current = myClaims.find(c => !c.isNext);

        // Queue: All isNext=true, sorted by end time (approx FIFO)
        const queue = myClaims
            .filter(c => c.isNext)
            .sort((a, b) => a.endTime - b.endTime);

        return {
            ...r,
            currentClaim: current || null,
            nextQueue: queue
        };
    });
  }, [claims]);


  // Main View: Only show OCCUPIED respawns
  const occupiedRespawns = derivedRespawns.filter(r => !!r.currentClaim);
  // Selector View: Only show FREE respawns
  const freeRespawns = derivedRespawns.filter(r => !r.currentClaim);

  // Calculate active respawn for modals
  const activeRespawn = useMemo(() => 
    derivedRespawns.find(r => r.id === activeRespawnId) || null, 
    [derivedRespawns, activeRespawnId]
  );

  // --- Handlers ---

  const handleOpenSelector = () => setSelectorOpen(true);

  const handleSelectFromList = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('CLAIM');
    setSelectorOpen(false); 
    setClaimModalOpen(true); 
  };

  const handleOpenClaim = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('CLAIM');
    setClaimModalOpen(true);
  };

  const handleOpenNext = (respawnId: string) => {
    setActiveRespawnId(respawnId);
    setModalMode('NEXT');
    setClaimModalOpen(true);
  };

  const handleCloseModals = () => {
    setClaimModalOpen(false);
    setSelectorOpen(false);
    setActiveRespawnId(null);
  };

  const handleModalSubmit = async (data: NewClaimData) => {
    if (!activeRespawnId || !userId) return;

    // We can use the memoized activeRespawn, but we need to check if it's still valid
    if (!activeRespawn) return;

    const now = Date.now();
    let startTime = now;
    let isNext = false;

    if (modalMode === 'NEXT') {
        isNext = true;
        // Calculate start time based on end of queue
        let lastEndTime = activeRespawn.currentClaim ? activeRespawn.currentClaim.endTime : now;
        if (activeRespawn.nextQueue.length > 0) {
          lastEndTime = activeRespawn.nextQueue[activeRespawn.nextQueue.length - 1].endTime;
        }
        startTime = lastEndTime;
    }

    const endTime = calculateEndTime(startTime, data.durationMinutes);

    // DB Insert
    const { error } = await supabase.from('claims').insert({
        respawn_id: activeRespawnId,
        user_id: userId,
        player_name: data.playerName,
        start_time: startTime,
        duration_minutes: data.durationMinutes,
        end_time: endTime,
        is_next: isNext,
        released_early: false
    });

    if (error) {
        alert("Erro ao agendar: " + error.message);
    }
  };

  const handleCancel = async (respawnId: string, claimId: string, isNext: boolean) => {
    // RLS in Supabase prevents deleting others' claims.
    // Logic here mirrors what the user intends.

    if (isNext) {
        // Just delete from queue
        await supabase.from('claims').delete().eq('id', claimId);
    } else {
        // Current Claim
        const respawn = derivedRespawns.find(r => r.id === respawnId);
        if (respawn && respawn.nextQueue.length > 0) {
            // If queue exists, mark as released (Yellow State)
             await supabase.from('claims').update({ released_early: true }).eq('id', claimId);
        } else {
            // No queue, just free the spot
            await supabase.from('claims').delete().eq('id', claimId);
        }
    }
  };

  const handleAnticipate = async (respawnId: string) => {
    const respawn = derivedRespawns.find(r => r.id === respawnId);
    if (!respawn || !respawn.currentClaim || respawn.nextQueue.length === 0) return;

    const oldClaim = respawn.currentClaim;
    const nextUp = respawn.nextQueue[0];

    const now = Date.now();
    const MAX_ALLOWED_MINUTES = respawn.isSpecial ? 195 : 140;

    // Calculate bonus time if previous user left early (visual only mostly, but good for data)
    let bonusMinutes = 0;
    if (oldClaim.endTime > now) {
        const diffMs = oldClaim.endTime - now;
        bonusMinutes = Math.floor(diffMs / (1000 * 60));
        if (bonusMinutes < 0) bonusMinutes = 0;
    }

    let potentialDuration = nextUp.durationMinutes + bonusMinutes;
    if (potentialDuration > MAX_ALLOWED_MINUTES) {
        potentialDuration = MAX_ALLOWED_MINUTES;
    }
    const newEndTime = calculateEndTime(now, potentialDuration);

    // 1. Delete old claim
    await supabase.from('claims').delete().eq('id', oldClaim.id);

    // 2. Promote Next claim
    await supabase.from('claims').update({
        is_next: false,
        start_time: now,
        duration_minutes: potentialDuration,
        end_time: newEndTime,
        released_early: false
    }).eq('id', nextUp.id);

    // 3. Update subsequent queue times
    let prevEnd = newEndTime;
    const remainingQueue = respawn.nextQueue.slice(1);
    for (const q of remainingQueue) {
        const qEnd = calculateEndTime(prevEnd, q.durationMinutes);
        await supabase.from('claims').update({
            start_time: prevEnd,
            end_time: qEnd
        }).eq('id', q.id);
        prevEnd = qEnd;
    }
  };

  if (authChecking) {
    return <div className="min-h-screen bg-[#0b1121] flex items-center justify-center"><RefreshCw className="animate-spin text-cyan-500" /></div>;
  }

  if (!isAuthenticated) {
    return <LoginPage onLogin={() => setIsAuthenticated(true)} />;
  }

  return (
    <div className="min-h-screen bg-[#0b1121] pb-20 selection:bg-cyan-500/30">

      {/* Header */}
      <header className="bg-[#0f172a]/80 backdrop-blur-md border-b border-cyan-900/30 sticky top-0 z-40 shadow-[0_4px_20px_-5px_rgba(8,145,178,0.1)]">
        <div className="container mx-auto px-4 py-3 flex flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-4">
            <div className="relative group shrink-0 hidden sm:block">
              <div className="absolute -inset-1 bg-gradient-to-r from-cyan-500 to-blue-600 rounded-lg blur opacity-40 group-hover:opacity-75 transition duration-200"></div>
              <div className="relative w-12 h-12 bg-[#0b1121] rounded-lg border border-cyan-800 flex flex-col items-center justify-center shadow-lg">
                 <ChevronUp size={28} className="text-cyan-400 -mb-2" strokeWidth={3} />
                 <span className="text-[10px] font-bold text-cyan-500 tracking-wider">MJR</span>
              </div>
            </div>

            <div>
              <h1 className="text-2xl sm:text-3xl font-bold text-white tracking-wider digital-font drop-shadow-[0_0_10px_rgba(34,211,238,0.3)]">
                CLAIMED
              </h1>
              <div className="flex items-center gap-2">
                <div className="h-[2px] w-4 bg-cyan-500 rounded-full"></div>
                <p className="text-[10px] text-cyan-400/80 tracking-[0.2em] uppercase font-bold">Monitor Ao Vivo</p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <button
                onClick={handleLogout}
                className="p-3 text-slate-400 hover:text-white hover:bg-slate-800 rounded-lg transition-colors"
                title="Sair / Logout"
            >
                <LogOut size={20} />
            </button>

            <button 
                onClick={handleOpenSelector}
                className="group relative inline-flex items-center justify-center gap-2 px-6 py-3 font-bold text-white transition-all duration-200 bg-cyan-600 font-lg rounded-lg hover:bg-cyan-500 hover:shadow-[0_0_20px_rgba(8,145,178,0.4)] focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-cyan-600 focus:ring-offset-slate-900"
            >
                <span className="absolute inset-0 w-full h-full -mt-1 rounded-lg opacity-30 bg-gradient-to-b from-transparent via-transparent to-black"></span>
                <Plus size={20} className="relative group-hover:rotate-90 transition-transform" strokeWidth={3} />
                <span className="relative uppercase tracking-widest text-sm hidden sm:inline">Novo Agendamento</span>
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-4 py-8">

        {/* Info Bar */}
        <div className="flex justify-between items-center mb-6 bg-[#1e293b]/30 p-4 rounded-md border-l-4 border-cyan-500 backdrop-blur-sm shadow-lg">
           <div className="text-xs text-cyan-600/80 flex items-center gap-2 uppercase tracking-wider font-bold">
             <RefreshCw size={12} className={`animate-spin-slow ${loadingClaims ? 'text-white' : ''}`} /> 
             {loadingClaims ? 'Sincronizando...' : 'Sistema Ativo'}
           </div>
           <div className="text-xs font-bold uppercase tracking-wider text-slate-400">
              Locais Ocupados: <span className="text-white">{occupiedRespawns.length}</span>
           </div>
        </div>

        {/* Occupied Grid */}
        {occupiedRespawns.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {occupiedRespawns.map(respawn => (
              <RespawnCard 
                key={respawn.id} 
                respawn={respawn}
                currentUserId={userId}
                onClaim={handleOpenClaim} 
                onNext={handleOpenNext}
                onCancel={handleCancel}
                onAnticipate={handleAnticipate}
              />
            ))}
          </div>
        ) : (
          <div className="text-center py-24 text-slate-600 border border-dashed border-slate-800 rounded-xl bg-slate-900/20">
             <div className="inline-block p-4 rounded-full bg-slate-900/50 mb-4 shadow-inner">
               <Search size={32} className="opacity-50" />
             </div>
             <p className="text-lg font-medium text-slate-400">NENHUMA HUNT ATIVA</p>
             <p className="text-xs uppercase tracking-widest text-slate-600 mt-1 mb-6">Todos os respawns estão livres no momento.</p>

             <button 
                onClick={handleOpenSelector}
                className="inline-flex items-center gap-2 text-cyan-400 hover:text-cyan-300 border border-cyan-900/50 hover:border-cyan-500/50 px-6 py-2 rounded uppercase font-bold text-xs tracking-widest transition-all"
             >
               <Plus size={14} /> Iniciar Sessão
             </button>
          </div>
        )}
      </main>

      {/* Modals */}
      <ClaimModal 
        isOpen={claimModalOpen}
        onClose={handleCloseModals}
        onSubmit={handleModalSubmit}
        respawn={activeRespawn}
        mode={modalMode}
      />

      <RespawnSelector 
        isOpen={selectorOpen}
        onClose={() => setSelectorOpen(false)}
        respawns={freeRespawns}
        onSelect={handleSelectFromList}
      />

    </div>
  );
}

export default App;

import React, { useState, useMemo } from 'react';
import { Search, Map, ChevronRight, X, ShieldCheck } from 'lucide-react';
import { Respawn } from '../types';

interface RespawnSelectorProps {
  isOpen: boolean;
  onClose: () => void;
  respawns: Respawn[]; // Should receive only FREE respawns
  onSelect: (respawnId: string) => void;
}

const RespawnSelector: React.FC<RespawnSelectorProps> = ({ isOpen, onClose, respawns, onSelect }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('ALL');

  const categories = useMemo(() => {
    const cats = new Set(respawns.map(r => r.category));
    return ['ALL', ...Array.from(cats).sort()];
  }, [respawns]);

  const filteredList = respawns.filter(r => {
    const matchesSearch = r.name.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = selectedCategory === 'ALL' || r.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-[#050b14]/90 backdrop-blur-md p-4 animate-in fade-in duration-200">
      <div className="bg-[#0f172a] border border-cyan-500/30 rounded-lg shadow-2xl w-full max-w-4xl h-[80vh] flex flex-col relative overflow-hidden">

        {/* Header */}
        <div className="p-5 border-b border-slate-800 bg-slate-900/80 flex justify-between items-center shrink-0">
          <div>
            <h2 className="text-2xl font-bold text-white digital-font tracking-wider flex items-center gap-2">
              <ShieldCheck className="text-emerald-400" />
              RESPAWNS DISPONÍVEIS
            </h2>
            <p className="text-slate-500 text-xs uppercase tracking-widest font-bold mt-1">Selecione um local para caçar</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Filters */}
        <div className="p-4 bg-[#0b1121] border-b border-slate-800 flex flex-col md:flex-row gap-4 shrink-0">
          <div className="relative flex-grow">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-cyan-700" size={18} />
            <input 
              type="text" 
              placeholder="BUSCAR POR NOME..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-[#1e293b] border border-slate-700 rounded-md py-3 pl-10 pr-4 text-sm text-white placeholder-slate-500 focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 outline-none uppercase font-medium"
              autoFocus
            />
          </div>
          <div className="relative w-full md:w-64">
            <Map className="absolute left-3 top-1/2 -translate-y-1/2 text-cyan-700" size={18} />
            <select 
              className="w-full bg-[#1e293b] border border-slate-700 rounded-md py-3 pl-10 pr-8 text-sm text-white appearance-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 outline-none cursor-pointer uppercase font-medium"
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value)}
            >
              {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
            </select>
          </div>
        </div>

        {/* List */}
        <div className="flex-grow overflow-y-auto p-4 space-y-2 custom-scrollbar bg-[#0b1121]">
          {filteredList.length > 0 ? (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              {filteredList.map(respawn => (
                <button 
                  key={respawn.id}
                  onClick={() => onSelect(respawn.id)}
                  className="flex items-center justify-between p-4 rounded bg-slate-800/40 border border-slate-700/50 hover:bg-cyan-950/30 hover:border-cyan-500/50 transition-all group text-left"
                >
                  <div>
                    <div className="font-bold text-slate-200 group-hover:text-cyan-300 transition-colors flex items-center gap-2">
                      {respawn.name}
                      {respawn.tier > 1 && (
                        <span className="text-[9px] bg-slate-900 text-cyan-500 px-1.5 rounded border border-cyan-900/50 font-mono">
                          T{respawn.tier}
                        </span>
                      )}
                    </div>
                    <div className="text-[10px] text-slate-500 uppercase tracking-widest mt-1 font-bold">
                      {respawn.category} {respawn.isSpecial && <span className="text-purple-400 ml-2">• Regra Especial</span>}
                    </div>
                  </div>
                  <ChevronRight size={18} className="text-slate-600 group-hover:text-cyan-400 group-hover:translate-x-1 transition-all" />
                </button>
              ))}
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-slate-600">
              <Search size={48} className="opacity-20 mb-4" />
              <p className="uppercase tracking-widest font-bold text-sm">Nenhum respawn encontrado</p>
            </div>
          )}
        </div>

        {/* Footer Stats */}
        <div className="p-3 bg-slate-900 border-t border-slate-800 flex justify-between items-center text-[10px] text-slate-500 uppercase font-bold tracking-widest shrink-0">
          <span>Mostrando {filteredList.length} resultados</span>
          <span className="text-emerald-500">Sistema Pronto</span>
        </div>

      </div>
    </div>
  );
};

export default RespawnSelector;

import React, { useState, useEffect } from 'react';
import { X, Clock, User, CheckCircle } from 'lucide-react';
import { NewClaimData, Respawn } from '../types';

interface ClaimModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (data: NewClaimData) => void;
  respawn: Respawn | null;
  mode: 'CLAIM' | 'NEXT';
}

const ClaimModal: React.FC<ClaimModalProps> = ({ isOpen, onClose, onSubmit, respawn, mode }) => {
  const [playerName, setPlayerName] = useState('');
  const [duration, setDuration] = useState(60); // Default 1 hour
  const [error, setError] = useState('');

  // Reset state when modal opens
  useEffect(() => {
    if (isOpen) {
      setPlayerName('');
      setDuration(60);
      setError('');
    }
  }, [isOpen]);

  if (!isOpen || !respawn) return null;

  // Constraints
  const MIN_MINUTES = 30;
  // Special: 3h 15m (195m)
  // Others: 2h 20m (140m)
  const MAX_MINUTES = respawn.isSpecial ? 195 : 140; 
  const MAX_DISPLAY = respawn.isSpecial ? "3h 15m" : "2h 20m";

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!playerName.trim()) {
      setError('Nome do personagem é obrigatório.');
      return;
    }
    if (duration < MIN_MINUTES || duration > MAX_MINUTES) {
      setError(`A duração deve ser entre 30 min e ${MAX_DISPLAY}.`);
      return;
    }
    onSubmit({ playerName, durationMinutes: duration });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-[#050b14]/80 backdrop-blur-sm p-4">
      <div className="bg-[#0f172a] border border-cyan-500/30 rounded shadow-[0_0_40px_-10px_rgba(8,145,178,0.3)] w-full max-w-md animate-in fade-in zoom-in duration-200 relative overflow-hidden">

        {/* Top Accent Line */}
        <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-cyan-600 to-blue-600"></div>

        <div className="flex justify-between items-center p-5 border-b border-slate-800 bg-slate-900/50">
          <div>
             <h3 className="text-xl font-bold text-white digital-font tracking-wider">
                {mode === 'CLAIM' ? 'AGENDAR HORÁRIO' : 'ENTRAR NA FILA'}
             </h3>
             <p className="text-[10px] text-cyan-500 uppercase tracking-widest font-bold">Protocolo: {mode === 'CLAIM' ? 'AGENDAMENTO' : 'NEXT'}</p>
          </div>
          <button onClick={onClose} className="text-slate-500 hover:text-cyan-400 transition-colors bg-slate-800/50 p-1.5 rounded-full hover:bg-slate-800">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          <div className="space-y-1 pb-2 border-b border-slate-800 border-dashed">
            <h4 className="text-lg font-bold text-cyan-100">{respawn.name}</h4>
            <span className="text-xs font-mono text-slate-500 uppercase tracking-widest">{respawn.category}</span>
          </div>

          <div className="space-y-5">
            {/* Player Name */}
            <div>
              <label className="block text-xs font-bold text-slate-400 mb-1.5 uppercase tracking-wide flex items-center gap-2">
                <User size={14} className="text-cyan-500" /> Nome do Personagem
              </label>
              <input
                type="text"
                value={playerName}
                onChange={(e) => setPlayerName(e.target.value)}
                placeholder="DIGITE O NOME..."
                className="w-full bg-[#0b1121] border border-slate-700 rounded px-4 py-2.5 text-white placeholder-slate-600 focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 outline-none transition-all font-medium"
                autoFocus
              />
            </div>

            {/* Duration */}
            <div>
              <label className="block text-xs font-bold text-slate-400 mb-1.5 uppercase tracking-wide flex items-center gap-2">
                <Clock size={14} className="text-cyan-500" /> Tempo de Hunt
              </label>
              <div className="flex items-center gap-4 bg-[#0b1121] p-3 rounded border border-slate-700">
                <input
                  type="range"
                  min={MIN_MINUTES}
                  max={MAX_MINUTES}
                  step={5}
                  value={duration}
                  onChange={(e) => setDuration(Number(e.target.value))}
                  className="flex-grow h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-cyan-500"
                />
                <div className="flex items-center bg-slate-800 rounded px-2 py-1 border border-slate-700 w-24 justify-center">
                    <span className="text-cyan-300 font-mono text-lg font-bold">{duration}</span>
                    <span className="text-xs text-slate-500 ml-1">min</span>
                </div>
              </div>
              <div className="flex justify-between mt-2 text-[10px] text-slate-500 font-mono">
                <span>MIN: 30m</span>
                <span className="text-cyan-600">MAX: {Math.floor(MAX_MINUTES/60)}h {MAX_MINUTES%60}m</span>
              </div>
            </div>
          </div>

          {error && (
            <div className="p-3 bg-rose-950/30 border-l-2 border-rose-500 text-rose-200 text-xs font-medium">
              ! {error}
            </div>
          )}

          <div className="flex gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 py-2.5 text-slate-400 hover:text-white border border-slate-700 hover:border-slate-500 rounded text-sm font-bold uppercase tracking-wide transition-colors"
            >
              Cancelar
            </button>
            <button
              type="submit"
              className="flex-[2] bg-gradient-to-r from-cyan-700 to-blue-600 hover:from-cyan-600 hover:to-blue-500 text-white text-sm font-bold uppercase tracking-wide py-2.5 rounded shadow-lg shadow-cyan-900/20 transition-all flex justify-center items-center gap-2"
            >
              <CheckCircle size={16} /> Confirmar
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

