            {isAdmin && (
                <button
                    onClick={() => setShowAdminPanel(true)}
                    className="flex items-center gap-2 px-3 py-2 bg-red-950/30 text-red-500 border border-red-900/50 hover:bg-red-900 hover:text-red-100 rounded-lg transition-all shadow-[0_0_10px_rgba(220,38,38,0.1)]"
                    title="Painel Administrativo"
                >
                    <ShieldAlert size={18} />
                    <span className="hidden md:inline text-xs font-bold uppercase tracking-wider">Admin</span>
                </button>
            )}

            {/* NOVO AGENDAMENTO (Styled like Admin but Blue) */}
            <button 
                onClick={handleOpenSelector}
                className="flex items-center gap-2 px-3 py-2 bg-cyan-950/30 text-cyan-500 border border-cyan-900/50 hover:bg-cyan-900 hover:text-cyan-100 rounded-lg transition-all shadow-[0_0_10px_rgba(8,145,178,0.1)]"
            >
                <Plus size={18} />
                <span className="hidden sm:inline text-xs font-bold uppercase tracking-wider">Novo Agendamento</span>
