  | "Ab'Dendriel" | "Ankrahmun" | "Carlin" | "Darashia" | "Edron" 
  | "Farmine" | "Feyrist" | "Gnomprona" | "Gray Island" | "Issavi" 
  | "Marapur" | "Oramond" | "Port Hope" | "Roshamuul" | "Rotten Blood" 
  | "Venore" | "Warzone" | "Yalahar" | "Criatura Boostada";

export interface Claim {
  id: string;
  userId: string; // ID of the user who created the claim (Essential for RLS UI checks)
  playerName: string;
  startTime: number; // timestamp
  durationMinutes: number;
  endTime: number; // timestamp
  isNext: boolean;
  releasedEarly?: boolean; // New flag: True if user canceled but queue exists
}

export interface Respawn {
  id: string;
  name: string;
  category: RespawnCategory;
  tier: number;
  isSpecial: boolean; // True for 3h 15m max, False for 2h 20m
  currentClaim: Claim | null;
  nextQueue: Claim[];
}

export interface NewClaimData {
  playerName: string;
  durationMinutes: number;
}

export interface GuildMember {
  name: string;
  title: string;
  rank: string;
  vocation: string;
  level: number;
  joined: string;
  status: 'online' | 'offline';
}

import React, { useState } from 'react';
import { Trash2, AlertTriangle, ShieldAlert, X, Users, RefreshCw, Search, List } from 'lucide-react';
import { GuildMember } from '../types';
import { formatEndTime, formatTimeRemaining } from '../utils/time';
import { INITIAL_RESPAWNS } from '../data/respawns';

interface AdminPanelProps {
  claims: any[]; // Raw claims from DB
  onClose: () => void;
  onForceDelete: (claimId: string) => Promise<void>;
}

type Tab = 'CLAIMS' | 'MEMBERS';

const AdminPanel: React.FC<AdminPanelProps> = ({ claims, onClose, onForceDelete }) => {
  const [activeTab, setActiveTab] = useState<Tab>('CLAIMS');
  const [deletingId, setDeletingId] = useState<string | null>(null);

  // Guild Member State
  const [members, setMembers] = useState<GuildMember[]>([]);
  const [syncing, setSyncing] = useState(false);
  const [memberSearch, setMemberSearch] = useState('');
  const [lastSyncTime, setLastSyncTime] = useState<string | null>(null);

  // Helper to get respawn name from ID
  const getRespawnName = (id: string) => {
    return INITIAL_RESPAWNS.find(r => r.id === id)?.name || id;
  };

  const handleDelete = async (id: string) => {
    if (confirm('TEM CERTEZA? Isso removerá o agendamento forçadamente.')) {
        setDeletingId(id);
        await onForceDelete(id);
        setDeletingId(null);
    }
  };

  // Sync Guild Data from TibiaData API
  const handleSyncGuild = async () => {
    setSyncing(true);
    try {
        const response = await fetch('https://api.tibiadata.com/v4/guild/Missclick');
        const data = await response.json();

        if (data && data.guild && data.guild.members) {
            setMembers(data.guild.members);
            const now = new Date();
            setLastSyncTime(now.toLocaleTimeString());
        }
    } catch (error) {
        console.error("Failed to sync guild data", error);
        alert("Falha ao sincronizar com a API do Tibia.");
    } finally {
        setSyncing(false);
    }
  };

  // Sort claims: Active first, then by time
  const sortedClaims = [...claims].sort((a, b) => {
      // Put "Next" queues at the bottom
      if (a.is_next !== b.is_next) return a.is_next ? 1 : -1;
      return a.end_time - b.end_time;
  });

  // Filter Members
  const filteredMembers = members.filter(m => 
      m.name.toLowerCase().includes(memberSearch.toLowerCase()) || 
      m.vocation.toLowerCase().includes(memberSearch.toLowerCase())
  );

  return (
    <div className="bg-[#0b1121] min-h-screen p-4 md:p-8 animate-in fade-in duration-300">

      <div className="max-w-7xl mx-auto space-y-6">

