                        onClick={() => setActiveTab('CLAIMS')}
                        className={`px-4 py-1.5 rounded text-xs font-bold uppercase tracking-wider transition-all flex items-center gap-2 ${activeTab === 'CLAIMS' ? 'bg-emerald-900/50 text-white shadow' : 'text-slate-500 hover:text-slate-300'}`}
