                        <span className="text-2xl font-mono text-white">{claims.length}</span>
                    </div>
                    <div className="bg-slate-900/50 p-4 rounded border border-slate-800 flex items-center justify-between">
                        <span className="text-slate-500 text-xs font-bold uppercase">Active Hunts</span>
                        <span className="text-2xl font-mono text-cyan-400">{claims.filter(c => !c.is_next).length}</span>
                    </div>
                    <div className="bg-slate-900/50 p-4 rounded border border-slate-800 flex items-center justify-between">
                        <span className="text-slate-500 text-xs font-bold uppercase">Queued (Next)</span>
                        <span className="text-2xl font-mono text-amber-400">{claims.filter(c => c.is_next).length}</span>
                    </div>
                </div>

                {/* Table */}
                <div className="bg-slate-900/30 border border-slate-800 rounded-lg overflow-hidden backdrop-blur-sm animate-in slide-in-from-bottom-4 fade-in">
                    <div className="overflow-x-auto">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-slate-950 border-b border-slate-800 text-xs text-slate-500 uppercase tracking-widest font-bold">
                                    <th className="p-4">Status</th>
                                    <th className="p-4">Respawn</th>
                                    <th className="p-4">Player Name</th>
                                    <th className="p-4">User ID (Auth)</th>
                                    <th className="p-4">Start Time</th>
                                    <th className="p-4">End Time</th>
                                    <th className="p-4 text-right">Ação</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-800 text-sm">
                                {sortedClaims.length > 0 ? (
                                    sortedClaims.map((claim) => (
                                        <tr key={claim.id} className="hover:bg-slate-800/30 transition-colors group">
                                            <td className="p-4">
                                                {claim.is_next ? (
                                                    <span className="inline-flex items-center px-2 py-1 rounded-full text-[10px] font-bold bg-amber-950/30 text-amber-500 border border-amber-900/50">
                                                        NEXT
                                                    </span>
                                                ) : (
                                                    <span className={`inline-flex items-center px-2 py-1 rounded-full text-[10px] font-bold border ${claim.released_early ? 'bg-yellow-950/30 text-yellow-500 border-yellow-900/50' : 'bg-emerald-950/30 text-emerald-500 border-emerald-900/50'}`}>
                                                        {claim.released_early ? 'SAIU' : 'ATIVO'}
                                                    </span>
                                                )}
                                            </td>
                                            <td className="p-4 font-bold text-slate-200">
                                                {getRespawnName(claim.respawn_id)}
                                                <span className="block text-[10px] text-slate-600 font-mono mt-0.5">{claim.respawn_id}</span>
                                            </td>
                                            <td className="p-4 text-cyan-300 font-medium">
                                                {claim.player_name}
                                            </td>
                                            <td className="p-4">
                                                <span className="font-mono text-[10px] text-slate-500 bg-slate-950 px-1 py-0.5 rounded">
                                                    {claim.user_id.substring(0, 8)}...
                                                </span>
                                            </td>
                                            <td className="p-4 text-slate-400 font-mono text-xs">
                                                {formatEndTime(claim.start_time)}
                                            </td>
                                            <td className="p-4 text-slate-300 font-mono text-xs">
                                                {formatEndTime(claim.end_time)}
                                                <span className="block text-[10px] text-slate-600">
                                                    {formatTimeRemaining(claim.end_time)} left
                                                </span>
                                            </td>
                                            <td className="p-4 text-right">
                                                <button 
                                                    onClick={() => handleDelete(claim.id)}
                                                    disabled={deletingId === claim.id}
                                                    className="p-2 bg-red-950/10 hover:bg-red-900/30 text-red-700 hover:text-red-400 border border-transparent hover:border-red-900 rounded transition-all group-hover:opacity-100 opacity-70"
                                                    title="Forçar Exclusão"
                                                >
                                                    {deletingId === claim.id ? (
                                                        <span className="animate-spin block w-4 h-4 border-2 border-red-500 border-t-transparent rounded-full"></span>
                                                    ) : (
                                                        <Trash2 size={16} />
                                                    )}
                                                </button>
                                            </td>
                                        </tr>
                                    ))
                                ) : (
                                    <tr>
                                        <td colSpan={7} className="p-12 text-center text-slate-600">
                                            <AlertTriangle size={32} className="mx-auto mb-3 opacity-20" />
                                            <p className="uppercase tracking-widest font-bold text-xs">Nenhum registro encontrado no banco de dados.</p>
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            </>
        )}

        {/* --- MEMBERS TAB --- */}
        {activeTab === 'MEMBERS' && (
            <div className="space-y-4 animate-in slide-in-from-bottom-2 fade-in">

                {/* Control Bar */}
                <div className="flex flex-col md:flex-row justify-between gap-4">
                    <div className="relative flex-1 max-w-md">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={14} />
                        <input 
                            type="text" 
                            placeholder="Buscar membro ou vocação..." 
                            value={memberSearch}
                            onChange={(e) => setMemberSearch(e.target.value)}
                            className="w-full bg-slate-900/30 hover:bg-slate-900/50 border border-slate-700/50 rounded py-2 pl-9 pr-4 text-slate-300 placeholder-slate-600 text-xs font-bold uppercase tracking-wider focus:border-emerald-500/50 focus:outline-none transition-all"
                        />
                    </div>

                    <div className="flex items-center gap-4">
                        {lastSyncTime && (
                            <span className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">
                                Última atualização: <span className="text-slate-300">{lastSyncTime}</span>
                            </span>
                        )}
                        <button 
                            onClick={handleSyncGuild}
                            disabled={syncing}
                            className="px-4 py-2 bg-cyan-900/30 hover:bg-cyan-900/50 text-cyan-400 border border-cyan-800/50 rounded flex items-center gap-2 text-xs font-bold uppercase tracking-wider transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            <RefreshCw size={14} className={syncing ? 'animate-spin' : ''} />
                            {syncing ? 'Sincronizando...' : 'Sync Missclick'}
                        </button>
                    </div>
                </div>

                {/* Members Table */}
                <div className="bg-slate-900/30 border border-slate-800 rounded-lg overflow-hidden backdrop-blur-sm h-[600px] flex flex-col">
                    <div className="overflow-y-auto custom-scrollbar flex-grow">
                        <table className="w-full text-left border-collapse relative">
                            <thead className="sticky top-0 z-10">
                                <tr className="bg-slate-950 border-b border-slate-800 text-xs text-slate-500 uppercase tracking-widest font-bold">
                                    <th className="p-4">Nome</th>
                                    <th className="p-4">Rank</th>
                                    <th className="p-4">Vocação</th>
                                    <th className="p-4">Level</th>
                                    <th className="p-4 text-right">Status</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-800 text-sm">
                                {filteredMembers.length > 0 ? (
                                    filteredMembers.map((member, idx) => (
                                        <tr key={idx} className="hover:bg-slate-800/30 transition-colors">
                                            <td className="p-3 pl-4 font-bold text-slate-200">
                                                {member.name}
                                                {member.title && <span className="block text-[10px] text-slate-500 font-normal italic">"{member.title}"</span>}
                                            </td>
                                            <td className="p-3 text-slate-400 text-xs font-medium">
                                                {member.rank}
                                            </td>
                                            <td className="p-3 text-slate-400 text-xs">
                                                {member.vocation}
                                            </td>
                                            <td className="p-3 text-slate-200 font-mono">
                                                {member.level}
                                            </td>
                                            <td className="p-3 pr-4 text-right">
                                                <div className={`inline-flex items-center gap-1.5 px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wide border ${member.status === 'online' ? 'bg-emerald-950/30 text-emerald-400 border-emerald-900/50' : 'bg-slate-800 text-slate-500 border-slate-700'}`}>
                                                    <span className={`w-1.5 h-1.5 rounded-full ${member.status === 'online' ? 'bg-emerald-400 animate-pulse' : 'bg-slate-500'}`}></span>
                                                    {member.status}
                                                </div>
                                            </td>
                                        </tr>
                                    ))
                                ) : (
                                    <tr>
                                        <td colSpan={5} className="p-12 text-center text-slate-600">
                                            {members.length === 0 ? (
                                                <div className="flex flex-col items-center">
                                                    <RefreshCw size={32} className="mb-3 opacity-20" />
                                                    <p className="uppercase tracking-widest font-bold text-xs mb-2">Lista vazia</p>
                                                    <p className="text-[10px] text-slate-600">Clique em Sync para carregar os dados da guilda.</p>
                                                </div>
                                            ) : (
                                                <p className="uppercase tracking-widest font-bold text-xs">Nenhum membro encontrado na busca.</p>
                                            )}
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>

                    {/* Footer Stats */}
                    <div className="bg-slate-950 border-t border-slate-800 p-3 flex justify-between items-center text-[10px] font-bold uppercase tracking-widest text-slate-500">
                        <span>Total: {members.length}</span>
                        <span className="flex gap-3">
                            <span className="text-emerald-500">Online: {members.filter(m => m.status === 'online').length}</span>
                            <span>Offline: {members.filter(m => m.status === 'offline').length}</span>
                        </span>
                    </div>
                </div>
            </div>
        )}

      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useMemo } from 'react';
import { Search, Map, ChevronRight, X, ShieldCheck } from 'lucide-react';
import { Respawn } from '../types';

interface RespawnSelectorProps {
  isOpen: boolean;
  onClose: () => void;
  respawns: Respawn[]; // Should receive only FREE respawns
  onSelect: (respawnId: string) => void;
}

const RespawnSelector: React.FC<RespawnSelectorProps> = ({ isOpen, onClose, respawns, onSelect }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('ALL');

  const categories = useMemo(() => {
    const cats = new Set(respawns.map(r => r.category));
    return ['ALL', ...Array.from(cats).sort()];
  }, [respawns]);

  const filteredList = respawns.filter(r => {
    const matchesSearch = r.name.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = selectedCategory === 'ALL' || r.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-[#050b14]/90 backdrop-blur-md p-4 animate-in fade-in duration-200">
      <div className="bg-[#0f172a] border border-cyan-500/30 rounded-lg shadow-2xl w-full max-w-4xl h-[80vh] flex flex-col relative overflow-hidden">

        {/* Header */}
        <div className="p-5 border-b border-slate-800 bg-slate-900/80 flex justify-between items-center shrink-0">
          <div>
            <h2 className="text-2xl font-bold text-white digital-font tracking-wider flex items-center gap-2">
              <ShieldCheck className="text-emerald-400" />
              RESPAWNS DISPONÍVEIS
            </h2>
            <p className="text-slate-500 text-xs uppercase tracking-widest font-bold mt-1">Selecione um local para caçar</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Filters */}
        <div className="p-4 bg-[#0b1121] border-b border-slate-800 flex flex-col md:flex-row gap-4 shrink-0">
          <div className="relative flex-grow">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-cyan-700" size={18} />
            <input 
              type="text" 
              placeholder="BUSCAR POR NOME..." 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full bg-[#1e293b] border border-slate-700 rounded-md py-3 pl-10 pr-4 text-sm text-white placeholder-slate-500 focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 outline-none uppercase font-medium"
              autoFocus
            />
          </div>
          <div className="relative w-full md:w-64">
            <Map className="absolute left-3 top-1/2 -translate-y-1/2 text-cyan-700" size={18} />
            <select 
              className="w-full bg-[#1e293b] border border-slate-700 rounded-md py-3 pl-10 pr-8 text-sm text-white appearance-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 outline-none cursor-pointer uppercase font-medium"
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value)}
            >
              {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
            </select>
          </div>
        </div>

        {/* List */}
        <div className="flex-grow overflow-y-auto p-4 space-y-2 custom-scrollbar bg-[#0b1121]">
          {filteredList.length > 0 ? (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              {filteredList.map(respawn => (
                <button 
                  key={respawn.id}
                  onClick={() => onSelect(respawn.id)}
                  className="flex items-center justify-between p-4 rounded bg-slate-800/40 border border-slate-700/50 hover:bg-cyan-950/30 hover:border-cyan-500/50 transition-all group text-left"
                >
                  <div>
                    <div className="font-bold text-slate-200 group-hover:text-cyan-300 transition-colors flex items-center gap-2">
                      {respawn.name}
                      <span className="text-[9px] bg-slate-900 text-cyan-500 px-1.5 rounded border border-cyan-900/50 font-mono">
                        T{respawn.tier}
                      </span>
                    </div>
                    <div className="text-[10px] text-slate-500 uppercase tracking-widest mt-1 font-bold">
                      {respawn.category} {respawn.isSpecial && <span className="text-purple-400 ml-2">• Regra Especial</span>}
                    </div>
                  </div>
                  <ChevronRight size={18} className="text-slate-600 group-hover:text-cyan-400 group-hover:translate-x-1 transition-all" />
                </button>
              ))}
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-slate-600">
              <Search size={48} className="opacity-20 mb-4" />
              <p className="uppercase tracking-widest font-bold text-sm">Nenhum respawn encontrado</p>
            </div>
          )}
        </div>

        {/* Footer Stats */}
        <div className="p-3 bg-slate-900 border-t border-slate-800 flex justify-between items-center text-[10px] text-slate-500 uppercase font-bold tracking-widest shrink-0">
          <span>Mostrando {filteredList.length} resultados</span>
          <span className="text-emerald-500">Sistema Pronto</span>
        </div>

      </div>
    </div>
  );
};

export default RespawnSelector;
